-- Schema for Domain: intellectual | Business: Pharmaceuticals | Version: v1_mvm
-- Generated on: 2026-05-05 21:10:58

-- ========= DATABASE =========
CREATE DATABASE IF NOT EXISTS `pharmaceuticals_ecm`.`intellectual` COMMENT 'SSOT for intellectual property portfolio including patents (NCE, NBE, formulations, processes), patent expiry timelines, exclusivity periods (orphan drug, data exclusivity, pediatric), trademark registrations, drug master files, freedom-to-operate analyses, and licensing agreements. Supports lifecycle management decisions, generic/biosimilar entry defense strategies, and coordination with legal counsel on patent litigation.';

-- ========= TABLES =========
CREATE OR REPLACE TABLE `pharmaceuticals_ecm`.`intellectual`.`patent` (
    `patent_id` BIGINT COMMENT 'Unique surrogate identifier for each patent record in the IP portfolio. Primary key for the patent master data product.',
    `country_id` BIGINT COMMENT 'Foreign key linking to masterdata.country. Business justification: Patents are jurisdiction-specific; essential for freedom-to-operate analysis, market entry planning, and regulatory strategy in global pharmaceutical operations.',
    `legal_entity_id` BIGINT COMMENT 'Foreign key linking to masterdata.legal_entity. Business justification: Patents are owned by legal entities; critical for IP ownership tracking, portfolio valuation, M&A due diligence, and financial reporting of intangible assets.',
    `atc_classification_id` BIGINT COMMENT 'Foreign key linking to masterdata.atc_classification. Business justification: Patents are classified by therapeutic area; essential for portfolio analysis, competitive benchmarking, and therapeutic area-specific IP strategy.',
    `cost_center_id` BIGINT COMMENT 'Foreign key linking to masterdata.cost_center. Business justification: Patents incur maintenance costs allocated to cost centers; required for IP budget management, financial planning, and cost allocation in pharmaceutical R&D.',
    `inn_registry_id` BIGINT COMMENT 'Foreign key linking to masterdata.inn_registry. Business justification: Patents claim specific INNs; essential for patent landscaping, FTO analysis, and molecule-patent linkage in pharmaceutical IP management.',
    `profit_center_id` BIGINT COMMENT 'Foreign key linking to masterdata.profit_center. Business justification: Patents are assigned to therapeutic areas/product lines represented by profit centers; critical for portfolio valuation, segment reporting, and strategic IP management.',
    `material_id` BIGINT COMMENT 'Foreign key linking to masterdata.material. Business justification: Patents cover specific materials (APIs, formulations); essential for product development, supply chain planning, and patent-product linkage in pharmaceutical operations.',
    `patent_family_id` BIGINT COMMENT 'Identifier grouping all related patent applications and grants that share a common priority filing across multiple jurisdictions. Used to manage global IP portfolio coherence and track international prosecution strategy.',
    `plant_id` BIGINT COMMENT 'Foreign key linking to masterdata.plant. Business justification: Manufacturing process patents are associated with specific plants; required for technology transfer, GMP compliance, and site-specific IP protection.',
    `adjusted_expiry_date` DATE COMMENT 'Final effective expiry date after applying all patent term adjustments (PTA), patent term extensions (PTE) for regulatory review delays, and supplementary protection certificates (SPC). Represents the true end of patent exclusivity for commercial planning purposes.',
    `annuity_paid_through_date` DATE COMMENT 'Date through which patent annuity (maintenance) fees have been paid, confirming the patent is in good standing. Used by IP operations to monitor fee payment compliance and prevent unintentional lapse.',
    `asset_classification` STRING COMMENT 'Broader intellectual property asset classification for this record. Primarily patent for this product, but also supports trade secrets and know-how records anchored to the patent master per the SSOT design. Enables unified IP portfolio reporting across asset types.. Valid values are `patent|trade_secret|know_how|trademark|dmf`',
    `created_timestamp` TIMESTAMP COMMENT 'Timestamp when this patent record was first created in the IP portfolio system. Supports audit trail, data lineage, and compliance with 21 CFR Part 11 electronic records requirements.',
    `data_exclusivity_expiry` DATE COMMENT 'Date on which regulatory data exclusivity (RDE) expires, preventing generic/biosimilar applicants from referencing the originators clinical data. In the US, NCEs receive 5 years; biologics receive 12 years under BPCIA. In the EU, the 8+2+1 rule applies. Complements patent expiry in LOE planning.',
    `expiry_date` DATE COMMENT 'Calculated or legally determined date on which patent protection lapses, typically 20 years from the filing date subject to patent term adjustments (PTA), patent term extensions (PTE), and supplementary protection certificates (SPC). The primary LOE (Loss of Exclusivity) planning anchor for lifecycle management and generic/biosimilar entry strategy.',
    `external_counsel_ref` STRING COMMENT 'Reference identifier or name of the external law firm or patent attorney managing prosecution, maintenance, or litigation for this patent. Supports coordination between in-house IP team and outside counsel.',
    `filing_date` DATE COMMENT 'Date on which the patent application was formally submitted to the patent office. Establishes the priority date for novelty assessment and is the anchor for calculating patent term and exclusivity periods.',
    `fto_clearance_status` STRING COMMENT 'Current freedom-to-operate (FTO) analysis status for this patent relative to the companys commercial activities. Cleared indicates no infringement risk identified; at_risk indicates potential third-party patent conflict; blocked indicates active infringement concern; under_review indicates ongoing FTO analysis. Critical for launch readiness and litigation risk management.. Valid values are `cleared|at_risk|blocked|under_review|not_assessed`',
    `grant_date` DATE COMMENT 'Date on which the patent was officially granted by the patent office, conferring enforceable rights to the assignee. Null for applications still under examination. Used to calculate patent term adjustments (PTA) and supplementary protection certificate (SPC) eligibility.',
    `legal_status` STRING COMMENT 'Current legal standing of the patent in its jurisdiction lifecycle. Pending indicates application under examination; granted indicates active protection; abandoned/lapsed indicates failure to prosecute or maintain; opposed indicates third-party challenge; litigated indicates active court proceedings. Drives LOE planning and portfolio valuation. [ENUM-REF-CANDIDATE: pending|granted|abandoned|expired|lapsed|opposed|litigated — promote to reference product]',
    `litigation_flag` BOOLEAN COMMENT 'Indicates whether this patent is currently subject to active litigation, including Paragraph IV ANDA challenges, inter partes review (IPR), post-grant review (PGR), or district court infringement proceedings. Triggers escalated monitoring and legal counsel coordination.',
    `maintenance_fee_due_date` DATE COMMENT 'Next scheduled date by which maintenance (annuity) fees must be paid to the patent office to keep the patent in force. Failure to pay results in lapse of patent rights. Critical for IP portfolio maintenance operations.',
    `orange_book_listed` BOOLEAN COMMENT 'Indicates whether this patent is listed in the FDA Approved Drug Products with Therapeutic Equivalence Evaluations (Orange Book). Orange Book listing triggers Paragraph IV certification obligations for ANDA filers and is central to Hatch-Waxman litigation strategy.',
    `orphan_drug_exclusivity_expiry` DATE COMMENT 'Date on which orphan drug market exclusivity expires, granting 7 years (US) or 10 years (EU) of market protection for drugs treating rare diseases. Distinct from patent expiry and critical for rare disease portfolio lifecycle planning.',
    `ownership_type` STRING COMMENT 'Classification of the companys relationship to the patent. Owned indicates full proprietary ownership; licensed_in indicates rights acquired from a third party; licensed_out indicates rights granted to a third party; co_owned indicates joint ownership; assigned indicates transfer of ownership has occurred.. Valid values are `owned|licensed_in|licensed_out|co_owned|assigned`',
    `patent_number` STRING COMMENT 'Officially assigned patent number issued by the relevant patent office (e.g., USPTO, EPO, WIPO). Serves as the primary external business identifier for the patent. Format varies by jurisdiction (e.g., US10123456B2, EP3456789A1).',
    `patent_type` STRING COMMENT 'Classification of the patent by the nature of the invention. Composition of matter covers the active molecule (NCE/NBE); method of use covers therapeutic indications; formulation covers drug product design; process covers manufacturing methods; polymorph and salt form cover physical-chemical variants. Critical for LOE (Loss of Exclusivity) strategy and generic/biosimilar entry defense.. Valid values are `composition_of_matter|method_of_use|formulation|process|polymorph|salt_form`',
    `pediatric_exclusivity_expiry` DATE COMMENT 'Date on which the 6-month pediatric exclusivity extension expires, granted by the FDA under the Best Pharmaceuticals for Children Act (BPCA) for conducting pediatric studies. Attaches to and extends both patent and data exclusivity periods.',
    `priority_date` DATE COMMENT 'Earliest claimed priority date, typically the date of the first-filed application in the patent family (provisional or national phase). Determines prior art cutoff and is critical for freedom-to-operate (FTO) analyses and validity challenges.',
    `prosecution_status` STRING COMMENT 'Detailed status of the patent application within the prosecution workflow at the patent office. Provides granular tracking beyond legal_status for IP counsel and patent attorneys managing active applications. [ENUM-REF-CANDIDATE: filed|examination|office_action|response_pending|allowed|granted|abandoned — promote to reference product]',
    `purple_book_listed` BOOLEAN COMMENT 'Indicates whether this patent is listed in the FDA Purple Book (List of Licensed Biological Products). Relevant for biologics and biosimilar entry defense under the Biologics Price Competition and Innovation Act (BPCIA).',
    `spc_expiry_date` DATE COMMENT 'Date on which the Supplementary Protection Certificate (SPC) expires, representing the final end of patent-based market exclusivity in the relevant EU jurisdiction. Null if no SPC applies.',
    `spc_number` STRING COMMENT 'Reference number of the Supplementary Protection Certificate (SPC) granted in EU member states to extend patent protection beyond the standard 20-year term to compensate for regulatory review time. Null if no SPC has been granted.',
    `term_adjustment_days` STRING COMMENT 'Number of days added to the patent term by the USPTO as Patent Term Adjustment (PTA) to compensate for delays in patent prosecution caused by the USPTO. Directly impacts the effective expiry date calculation.',
    `term_extension_days` STRING COMMENT 'Number of days added to the patent term under 35 U.S.C. § 156 (US) to compensate for time lost during FDA regulatory review of the drug product. Maximum extension is 5 years; total remaining term cannot exceed 14 years post-approval.',
    `therapeutic_area` STRING COMMENT 'Primary therapeutic area or disease category addressed by the patented compound or method (e.g., Oncology, Immunology, Rare Diseases, Cardiovascular, Neuroscience). Aligns with the companys R&D portfolio structure and supports commercial lifecycle planning.',
    `title` STRING COMMENT 'Official title of the patent as filed and granted by the patent office. Describes the invention in human-readable form and is used for portfolio reporting and IP management.',
    `updated_timestamp` TIMESTAMP COMMENT 'Timestamp of the most recent update to this patent record. Used for change tracking, data synchronization, and audit compliance under 21 CFR Part 11.',
    `veeva_vault_doc_reference` STRING COMMENT 'Reference identifier linking this patent record to the corresponding document stored in Veeva Vault (RIM or QualityDocs module), where the patent application, grant certificate, and related correspondence are archived. Supports traceability to the system of record for IP documents.',
    CONSTRAINT pk_patent PRIMARY KEY(`patent_id`)
) COMMENT 'Core master record for all pharmaceutical patents owned or licensed by the company. Captures patent number, title, filing/grant/expiry dates, patent family reference, jurisdiction, patent type (composition of matter, method of use, formulation, process, polymorph, salt form), covered compound (INN/USAN), therapeutic area, legal status, and assignee. Also serves as the anchor for trade secrets and know-how records via asset classification. SSOT for the IP portfolio — anchors lifecycle management, LOE planning, litigation defense, and generic/biosimilar entry strategy.';

CREATE OR REPLACE TABLE `pharmaceuticals_ecm`.`intellectual`.`patent_claim` (
    `patent_claim_id` BIGINT COMMENT 'Unique surrogate identifier for each individual patent claim record within the intellectual property portfolio management system.',
    `country_id` BIGINT COMMENT 'Foreign key linking to masterdata.country. Business justification: Patent claims are jurisdiction-specific; critical for patent prosecution strategy, litigation planning, and claim scope analysis in pharmaceutical IP management.',
    `drug_product_id` BIGINT COMMENT 'Foreign key linking to product.drug_product. Business justification: Specific patent claims cover specific products. Essential for FTO analysis, claim construction in litigation, Orange Book listing accuracy, and claim-level infringement assessment. Removes denormalize',
    `drug_substance_id` BIGINT COMMENT 'Foreign key linking to product.drug_substance. Business justification: Composition-of-matter and salt-form patent claims cover specific drug substances. IP teams need to link patent claims to drug substances for FTO analysis, claim scope assessment, and validity challeng',
    `formulation_id` BIGINT COMMENT 'Foreign key linking to product.formulation. Business justification: Formulation patent claims (e.g., extended-release, nanoparticle) cover specific formulations. IP teams link patent claims to formulations for FTO clearance, claim mapping during ANDA challenges, and d',
    `atc_classification_id` BIGINT COMMENT 'Foreign key linking to masterdata.atc_classification. Business justification: Patent claim portfolio segmentation by ATC class is required for competitive intelligence reports and IP strategy by therapeutic area. A pharma IP expert expects claims to be classifiable by ATC. No e',
    `inn_registry_id` BIGINT COMMENT 'Foreign key linking to masterdata.inn_registry. Business justification: IP portfolio management requires linking patent claims to the specific INN (active substance) they protect. FTO analysis and regulatory submissions depend on knowing which INN each claim covers. No ex',
    `material_id` BIGINT COMMENT 'Foreign key linking to masterdata.material. Business justification: Manufacturing FTO clearance requires linking patent claims to the specific material (API or formulation) they cover. Supply chain IP risk assessment depends on this link. No existing material FK on pa',
    `orange_book_listing_id` BIGINT COMMENT 'Foreign key linking to intellectual.orange_book_listing. Business justification: patent_claim has is_orange_book_listed (BOOLEAN) indicating whether the specific claim is listed in the Orange Book. The actual listing record is in orange_book_listing. Adding a FK normalizes this — ',
    `business_partner_id` BIGINT COMMENT 'Foreign key linking to masterdata.business_partner. Business justification: Outside counsel firms handling patent claim prosecution are business partners in the vendor master. Linking enables legal spend management and AP payment processing. outside_counsel_firm is a denormal',
    `patent_id` BIGINT COMMENT 'Reference to the parent patent record to which this claim belongs. Each patent may contain multiple independent and dependent claims.',
    `amendment_date` DATE COMMENT 'The date on which the most recent amendment to this claim was filed or entered. Null if the claim has never been amended. Used to track prosecution history and assess prosecution history estoppel in infringement proceedings.',
    `application_number` STRING COMMENT 'The official application number assigned by the patent office upon filing (e.g., US 16/123,456 or EP 19 123 456.7). Used to track prosecution history, office actions, and correspondence with patent counsel. Serves as the primary external identifier for the application.',
    `challenge_status` STRING COMMENT 'Indicates whether the claim is subject to an active or completed post-grant challenge. IPR (Inter Partes Review) and opposition proceedings can invalidate individual claims independently. Critical for generic/biosimilar entry defense and Paragraph IV ANDA litigation strategy.. Valid values are `not_challenged|ipr_pending|ipr_final|opposition_pending|reexamination|litigation`',
    `claim_amendment_version` STRING COMMENT 'Version number tracking amendments made to the claim text during prosecution or post-grant proceedings (e.g., reexamination, IPR). Version 1 represents the originally filed claim; subsequent versions reflect amendments. Used to maintain prosecution history and support claim construction arguments.',
    `claim_category` STRING COMMENT 'Subject matter category of the claim defining what is being protected. Composition claims protect chemical or biological entities (NCE, NBE, API); method/use claims protect therapeutic uses or manufacturing processes; formulation claims protect drug product (DP) compositions; dosage form claims protect FDF configurations. [ENUM-REF-CANDIDATE: composition|method|process|apparatus|use|formulation|dosage_form|biological — promote to reference product]',
    `claim_number` STRING COMMENT 'Sequential number of the claim within the patent document as filed or granted (e.g., Claim 1, Claim 2). Claim numbering follows USPTO and EPO conventions and is used in legal proceedings, IPR petitions, and freedom-to-operate analyses.',
    `claim_priority_date` DATE COMMENT 'The earliest effective filing date from which this claims priority is established, including priority claims under Paris Convention or PCT. The priority date determines prior art cutoff and is critical for validity assessments and patent term calculations.',
    `claim_scope_classification` STRING COMMENT 'Business classification of the claims legal breadth and coverage. Broad claims cover wide ranges of embodiments; narrow claims are limited to specific embodiments. Genus claims cover a class of compounds or methods; species claims cover a specific member. Used in lifecycle management and generic/biosimilar entry defense strategy.. Valid values are `broad|narrow|genus|species`',
    `claim_text` STRING COMMENT 'Full verbatim text of the claim as it appears in the granted patent or pending application. This is the legally operative language used in infringement assessments, IPR petitions, inter partes review proceedings, and freedom-to-operate (FTO) analyses. Classified confidential due to strategic IP sensitivity.',
    `claim_type` STRING COMMENT 'Structural classification of the claim indicating whether it stands alone (independent) or references and narrows a prior claim (dependent or multiple dependent). Independent claims define the broadest scope; dependent claims add limitations. Critical for infringement analysis and claim charting.. Valid values are `independent|dependent|multiple_dependent`',
    `cpc_classification_code` STRING COMMENT 'The Cooperative Patent Classification (CPC) code assigned by USPTO or EPO, providing more granular technical classification than IPC. Used in patent landscape analyses, freedom-to-operate searches, and competitive intelligence for drug discovery and CMC domains.',
    `created_timestamp` TIMESTAMP COMMENT 'The timestamp when this patent claim record was first created in the IP management system. Used for audit trail, data lineage, and compliance with 21 CFR Part 11 electronic records requirements.',
    `data_source_system` STRING COMMENT 'Identifies the operational system of record from which this patent claim record originated. Supports data lineage, reconciliation, and audit trail requirements. Veeva Vault RIM is the primary system of record for IP and regulatory data in the pharmaceutical enterprise.. Valid values are `Veeva_Vault_RIM|SAP_S4HANA|Manual_Entry|Patent_Docketing_System|External_Feed`',
    `expiry_date` DATE COMMENT 'The calculated expiration date of the patent claim, accounting for standard 20-year patent term from filing date, patent term adjustments (PTA), and patent term extensions (PTE) granted for regulatory review delays under Hatch-Waxman or SPC in Europe. Critical for lifecycle management and loss-of-exclusivity (LOE) planning.',
    `filing_date` DATE COMMENT 'The date on which the patent application containing this claim was filed with the relevant patent office. Used to calculate patent term and determine prior art under AIA first-inventor-to-file rules.',
    `fto_relevance_flag` BOOLEAN COMMENT 'Indicates whether this claim has been identified as relevant in one or more freedom-to-operate (FTO) analyses. FTO-relevant claims require monitoring for potential infringement by third-party products or by the companys own pipeline compounds.',
    `grant_date` DATE COMMENT 'The date on which the patent containing this claim was officially granted by the patent office. Marks the start of the enforceable patent term. Null for pending applications.',
    `ipc_classification_code` STRING COMMENT 'The International Patent Classification (IPC) code assigned to this claim, indicating the technical field of the invention (e.g., A61K for pharmaceutical preparations, A61P for therapeutic activity). Used for patent landscape analyses, competitive intelligence, and prior art searches.',
    `ipr_petition_number` STRING COMMENT 'The official PTAB (Patent Trial and Appeal Board) or EPO Opposition Division case number for any active or completed inter partes review (IPR) or opposition proceeding challenging this claim. Null if no IPR or opposition has been filed. Critical for litigation tracking and generic/biosimilar defense strategy.',
    `is_purple_book_listed` BOOLEAN COMMENT 'Indicates whether this claim is associated with a patent listed in the FDA Purple Book (Lists of Licensed Biological Products). Purple Book listing is relevant for biosimilar entry defense under the Biologics Price Competition and Innovation Act (BPCIA) patent dance provisions.',
    `last_updated_timestamp` TIMESTAMP COMMENT 'The timestamp when this patent claim record was most recently modified in the IP management system. Used for change tracking, audit trail, and data synchronization with Veeva Vault RIM and external patent docketing systems.',
    `litigation_case_reference` STRING COMMENT 'Court case number or docket reference for any active or completed patent infringement litigation involving this claim (e.g., Paragraph IV ANDA litigation, biosimilar patent dance disputes). Classified confidential due to legal privilege sensitivity. Null if no litigation is associated.',
    `molecule_type` STRING COMMENT 'Classification of the molecule or biological entity protected by this claim. NCE (New Chemical Entity) for small molecules; NBE (New Biological Entity) for large molecule biologics; biosimilar for follow-on biologics; vaccine, gene therapy, or cell therapy for advanced therapy medicinal products (ATMPs). Determines applicable regulatory pathway and exclusivity provisions.. Valid values are `NCE|NBE|biosimilar|vaccine|gene_therapy|cell_therapy`',
    `parent_claim_number` STRING COMMENT 'For dependent claims, the claim number of the parent claim from which this claim depends. Null for independent claims. Used to reconstruct claim dependency trees for infringement and validity analyses.',
    `patent_office_code` STRING COMMENT 'Code identifying the patent office where this claim was filed or is being prosecuted. USPTO (US), EPO (European), UKIPO (UK post-Brexit), JPO (Japan), CNIPA (China), WIPO (PCT international). Determines applicable procedural rules and examination standards. [ENUM-REF-CANDIDATE: USPTO|EPO|UKIPO|JPO|CNIPA|WIPO|PMDA — 7 candidates stripped; promote to reference product]',
    `patent_term_extension_months` STRING COMMENT 'Number of months of patent term extension granted to compensate for regulatory review delays during NDA/BLA/MAA approval processes. In the US, PTE is granted under 35 U.S.C. § 156 (Hatch-Waxman); in Europe, via Supplementary Protection Certificate (SPC). Directly impacts loss-of-exclusivity (LOE) date calculations.',
    `prosecution_status` STRING COMMENT 'Current status of the claim within the patent prosecution lifecycle at the relevant patent office. Pending claims are under examination; allowed claims have been approved but not yet granted; granted claims are part of an issued patent; rejected claims received a final office action; abandoned claims were not pursued further.. Valid values are `pending|allowed|granted|rejected|abandoned|withdrawn`',
    `spc_number` STRING COMMENT 'The official reference number of the Supplementary Protection Certificate (SPC) granted in EU member states for this claim. SPCs extend effective patent protection for up to 5 years post-patent expiry for medicinal products that required regulatory approval. Null if no SPC has been granted.',
    `therapeutic_area` STRING COMMENT 'The therapeutic area or disease indication covered by this claim (e.g., Oncology, Immunology, Rare Diseases, Cardiovascular). Aligns with the companys portfolio therapeutic areas and is used for lifecycle management, LOE planning, and commercial strategy coordination.',
    `validity_status` STRING COMMENT 'Current legal standing of the claim. Valid claims are enforceable; invalid claims have been found unpatentable; cancelled claims were withdrawn during prosecution or post-grant proceedings; amended claims were modified during IPR or reexamination; under_review indicates active challenge proceedings; stayed indicates enforcement is paused pending litigation outcome.. Valid values are `valid|invalid|cancelled|amended|under_review|stayed`',
    CONSTRAINT pk_patent_claim PRIMARY KEY(`patent_claim_id`)
) COMMENT 'Individual claims within a granted or pending patent, capturing claim number, claim type (independent, dependent), claim text, claim scope classification (broad, narrow, genus, species), and validity status. Critical for freedom-to-operate analyses, infringement assessments, and generic/biosimilar entry defense strategies. Each claim has its own legal standing and may be challenged independently during inter partes review (IPR) or opposition proceedings.';

CREATE OR REPLACE TABLE `pharmaceuticals_ecm`.`intellectual`.`patent_family` (
    `patent_family_id` BIGINT COMMENT 'Unique surrogate identifier for the patent family record in the Pharmaceuticals IP portfolio system. Primary key for this entity.',
    `legal_entity_id` BIGINT COMMENT 'Foreign key linking to masterdata.legal_entity. Business justification: Patent families are owned by legal entities; essential for portfolio valuation, corporate structure reporting, and strategic IP management across business units.',
    `atc_classification_id` BIGINT COMMENT 'Foreign key linking to masterdata.atc_classification. Business justification: Patent families are organized by therapeutic area; required for strategic portfolio management, competitive intelligence, and therapeutic area investment decisions.',
    `cost_center_id` BIGINT COMMENT 'Foreign key linking to masterdata.cost_center. Business justification: Patent families are managed by business units with cost center allocation; essential for portfolio budgeting, cost tracking, and financial accountability.',
    `inn_registry_id` BIGINT COMMENT 'Foreign key linking to masterdata.inn_registry. Business justification: Patent families cover specific INNs; required for competitive intelligence, portfolio strategy, and molecule-specific IP protection planning.',
    `profit_center_id` BIGINT COMMENT 'Foreign key linking to masterdata.profit_center. Business justification: Patent families align with business segments; essential for strategic portfolio management, segment P&L, and therapeutic area performance tracking.',
    `material_id` BIGINT COMMENT 'Foreign key linking to masterdata.material. Business justification: IP portfolio management links patent families to the materials (APIs/formulations) they protect, enabling supply chain IP risk assessment and licensing scope determination. A pharma IP expert expects ',
    `country_id` BIGINT COMMENT 'Foreign key linking to masterdata.country. Business justification: Priority country is fundamental to patent family strategy and filing decisions; required for PCT strategy and global patent portfolio management.',
    `created_timestamp` TIMESTAMP COMMENT 'Timestamp when the patent family record was first created in the IP data system. Supports audit trail requirements under 21 CFR Part 11 and data lineage tracking in the Databricks Silver Layer.',
    `data_exclusivity_expiry_date` DATE COMMENT 'The date on which regulatory data exclusivity (RDE) protection expires for the drug covered by this patent family. Data exclusivity prevents generic/biosimilar applicants from referencing the originators clinical data for a defined period (e.g., 5 years NCE in US, 8+2+1 years in EU).',
    `dmf_reference_number` STRING COMMENT 'The FDA Drug Master File (DMF) number or equivalent regulatory dossier reference associated with the API or formulation covered by this patent family. Links IP protection to the regulatory submission record.',
    `earliest_expiry_date` DATE COMMENT 'The earliest expiration date among all granted member patents in the family, before any patent term extensions or supplementary protection certificates. Critical for generic/biosimilar entry defense strategy planning.',
    `family_code` STRING COMMENT 'Internally assigned alphanumeric code uniquely identifying the patent family within the IP management system. Used for cross-referencing across Veeva Vault RIM and SAP IP modules.. Valid values are `^[A-Z0-9-]{3,30}$`',
    `family_name` STRING COMMENT 'Descriptive name assigned to the patent family, typically reflecting the invention title or the compound/technology it covers (e.g., Compound X Formulation Family).',
    `family_status` STRING COMMENT 'Current lifecycle status of the patent family. Active indicates at least one member patent is in force; Pending indicates applications under examination; Expired indicates all members have lapsed; Abandoned indicates prosecution was discontinued. [ENUM-REF-CANDIDATE: active|pending|expired|abandoned|licensed_out|litigated — promote to reference product]. Valid values are `active|pending|expired|abandoned|licensed_out|litigated`',
    `family_type` STRING COMMENT 'Classification of the patent family grouping methodology. Simple groups patents sharing the same priority; Extended includes equivalents; INPADOC follows the European Patent Office INPADOC definition. [ENUM-REF-CANDIDATE: simple|extended|INPADOC|domestic|international — promote to reference product]. Valid values are `simple|extended|INPADOC|domestic|international`',
    `filing_date` DATE COMMENT 'The date on which the patent family record was formally established in the IP management system, typically corresponding to the priority application filing date. Used for portfolio age analysis and lifecycle tracking.',
    `freedom_to_operate_status` STRING COMMENT 'Current status of the Freedom-to-Operate (FTO) analysis for this patent family. Cleared indicates no blocking third-party patents identified; At Risk indicates potential infringement risk; Blocked indicates a blocking patent exists; Under Review indicates analysis in progress.. Valid values are `cleared|at_risk|blocked|under_review|not_assessed`',
    `granted_member_count` STRING COMMENT 'Number of patent applications within the family that have been granted (issued) patents across all jurisdictions. Distinguishes granted protection from pending applications for portfolio strength assessment.',
    `invention_category` STRING COMMENT 'Classification of the type of invention covered by the patent family. New Chemical Entity (NCE) covers novel small molecules; New Biological Entity (NBE) covers biologics; formulation covers drug product compositions; process covers manufacturing methods; method_of_use covers therapeutic indications. [ENUM-REF-CANDIDATE: NCE|NBE|formulation|process|combination|device|method_of_use — promote to reference product]',
    `invention_title` STRING COMMENT 'The official title of the invention as stated in the priority or PCT application. Reflects the technical scope of the patent family and is used for portfolio reporting and IP strategy communications.',
    `jurisdiction_count` STRING COMMENT 'Number of distinct national or regional jurisdictions in which the patent family has at least one active member application or granted patent. Measures geographic breadth of IP protection.',
    `last_updated_timestamp` TIMESTAMP COMMENT 'Timestamp of the most recent update to the patent family record. Supports change tracking, audit compliance under 21 CFR Part 11, and incremental data loading in the Databricks Silver Layer.',
    `latest_expiry_date` DATE COMMENT 'The latest expiration date among all granted member patents in the family, including any patent term extensions (PTE) or supplementary protection certificates (SPC). Defines the outer boundary of IP exclusivity for lifecycle management.',
    `licensing_status` STRING COMMENT 'Indicates whether the patent family is subject to a licensing arrangement. Licensed In means the company holds a license from a third party; Licensed Out means the company has granted a license to a third party; Cross Licensed indicates a bilateral arrangement.. Valid values are `not_licensed|licensed_in|licensed_out|cross_licensed|sublicensed`',
    `litigation_status` STRING COMMENT 'Current litigation status associated with this patent family. Tracks whether the family is subject to active patent infringement suits, inter partes review (IPR), or post-grant review (PGR) proceedings. [ENUM-REF-CANDIDATE: none|threatened|filed|settled|judgment_for_patentee|judgment_against — promote to reference product]. Valid values are `none|threatened|filed|settled|judgment_for_patentee|judgment_against`',
    `member_count` STRING COMMENT 'Total number of individual patent applications and granted patents that are members of this family across all jurisdictions. Indicates the breadth of global IP coverage for the invention.',
    `notes` STRING COMMENT 'Free-text field for IP counsel to record strategic observations, prosecution history highlights, licensing negotiation context, or lifecycle management decisions relevant to the patent family. Not intended for structured data.',
    `orange_book_listed` BOOLEAN COMMENT 'Indicates whether one or more patents in this family are listed in the FDA Approved Drug Products with Therapeutic Equivalence Evaluations (Orange Book). Orange Book listing triggers 30-month stay provisions against ANDA filers under Hatch-Waxman.',
    `orphan_drug_exclusivity_flag` BOOLEAN COMMENT 'Indicates whether the invention covered by this patent family has been granted orphan drug designation and associated market exclusivity (7 years in the US, 10 years in the EU). Relevant for rare disease portfolio strategy.',
    `patent_register_listed` BOOLEAN COMMENT 'Indicates whether patents in this family are listed on the EMA European Patent Register or national patent registers linked to marketing authorisations, triggering data exclusivity and market protection provisions.',
    `patent_term_extension_granted` BOOLEAN COMMENT 'Indicates whether a Patent Term Extension (PTE) or Supplementary Protection Certificate (SPC) has been granted for any member of this family, compensating for regulatory review time under FDA or EMA processes.',
    `pct_application_number` STRING COMMENT 'The international application number filed under the Patent Cooperation Treaty (PCT) administered by WIPO, if applicable. Format: PCT/[country code][year]/[serial number]. Enables simultaneous patent protection in multiple jurisdictions.. Valid values are `^PCT/[A-Z]{2}[0-9]{4}/[0-9]{6}$`',
    `pct_filing_date` DATE COMMENT 'The international filing date of the PCT application, if applicable. Determines the 30/31-month national phase entry deadline for member jurisdictions.',
    `pct_publication_number` STRING COMMENT 'The WIPO publication number assigned to the PCT international application upon publication (e.g., WO2023/123456). Used for public disclosure tracking and prior art searches.. Valid values are `^WO[0-9]{4}/[0-9]{6}$`',
    `pediatric_exclusivity_expiry_date` DATE COMMENT 'The expiry date of pediatric exclusivity granted under the Best Pharmaceuticals for Children Act (BPCA) in the US or the Paediatric Regulation in the EU, adding 6 months of additional exclusivity to qualifying patents.',
    `portfolio_segment` STRING COMMENT 'Strategic classification of the patent family within the IP portfolio. Core patents protect primary commercial products; Defensive patents block competitor freedom to operate; Licensing patents are monetized through out-licensing; Acquired patents came through M&A.. Valid values are `core|defensive|licensing|divested|acquired|collaborative`',
    `priority_application_number` STRING COMMENT 'The application number of the earliest-filed patent application that establishes the priority date for the family. Typically a national or regional application number (e.g., US provisional or EP application).',
    `priority_date` DATE COMMENT 'The filing date of the earliest priority application in the family. Establishes the effective date of invention disclosure for novelty and prior art assessments under Paris Convention.',
    `responsible_ip_counsel` STRING COMMENT 'Name or identifier of the internal IP attorney or external patent counsel responsible for managing prosecution and maintenance of this patent family. Used for accountability and workload management in the IP department.',
    `therapeutic_area` STRING COMMENT 'The primary therapeutic area or disease indication covered by the invention (e.g., Oncology, Immunology, Rare Diseases, Cardiovascular). Aligns with the companys portfolio therapeutic area taxonomy for lifecycle management reporting.',
    CONSTRAINT pk_patent_family PRIMARY KEY(`patent_family_id`)
) COMMENT 'Groups related patents and patent applications filed across multiple jurisdictions that share a common priority application. Tracks the priority application number, priority date, PCT application number, family type (simple, extended, INPADOC), and member count. Enables portfolio-level analysis of global IP coverage for a given invention and supports lifecycle management across jurisdictions.';

CREATE OR REPLACE TABLE `pharmaceuticals_ecm`.`intellectual`.`exclusivity_period` (
    `exclusivity_period_id` BIGINT COMMENT 'Unique surrogate identifier for each regulatory exclusivity period record in the pharmaceutical intellectual property portfolio.',
    `country_id` BIGINT COMMENT 'Foreign key linking to masterdata.country. Business justification: Exclusivity is jurisdiction-specific; essential for lifecycle management, LOE planning, and market-specific revenue forecasting in pharmaceutical commercialization.',
    `drug_product_id` BIGINT COMMENT 'Foreign key linking to product.drug_product. Business justification: Exclusivity periods apply to specific drug products (dosage form and strength combinations). FDA exclusivity codes are assigned at the drug product level. Regulatory teams need this link for LOE plann',
    `legal_entity_id` BIGINT COMMENT 'Foreign key linking to masterdata.legal_entity. Business justification: Exclusivity periods are granted to and held by a specific legal entity (Marketing Authorization Holder). Regulatory submissions, LOE planning, and legal entity IP asset reporting all require knowing w',
    `atc_classification_id` BIGINT COMMENT 'Foreign key linking to masterdata.atc_classification. Business justification: Exclusivity is granted for specific therapeutic indications; required for competitive intelligence, market analysis, and therapeutic area-specific LOE planning.',
    `cost_center_id` BIGINT COMMENT 'Foreign key linking to masterdata.cost_center. Business justification: LOE (loss of exclusivity) defense activities and exclusivity maintenance costs are tracked against cost centers for IP budget management and financial planning. No existing cost_center FK on exclusivi',
    `inn_registry_id` BIGINT COMMENT 'Foreign key linking to masterdata.inn_registry. Business justification: Exclusivity is granted for specific INNs; critical for lifecycle management, molecule-specific LOE planning, and regulatory exclusivity tracking.',
    `masterdata_ndc_code_id` BIGINT COMMENT 'Foreign key linking to masterdata.ndc_code. Business justification: Exclusivity protects specific NDC-coded products; critical for LOE forecasting, generic entry planning, and product-specific revenue protection.',
    `medicinal_product_id` BIGINT COMMENT 'Reference to the pharmaceutical product (Drug Product or Drug Substance) to which this exclusivity period applies.',
    `patent_id` BIGINT COMMENT 'FK to intellectual.patent.patent_id — Exclusivity periods are often tied to specific patents — linking enables IP lifecycle management and loss-of-exclusivity (LOE) planning critical for commercial strategy.',
    `approval_date` DATE COMMENT 'The date on which the NDA, BLA, or MAA was approved by the granting authority, which typically triggers the start of the exclusivity period. Serves as the anchor date for exclusivity calculations.',
    `brand_name` STRING COMMENT 'The proprietary/trade name of the drug product under which the exclusivity was granted and the product is marketed. Used for commercial lifecycle management and trademark coordination.',
    `challenge_status` STRING COMMENT 'Indicates whether this exclusivity period is subject to a legal or regulatory challenge. Paragraph IV = ANDA Paragraph IV certification challenge under Hatch-Waxman; Inter Partes = IPR/PGR challenge at USPTO; Court Order = court-ordered modification; Under Review = authority-initiated review. Critical for generic entry defense strategy.. Valid values are `none|paragraph_iv|inter_partes|court_order|under_review`',
    `created_timestamp` TIMESTAMP COMMENT 'Timestamp when this exclusivity period record was first created in the system, supporting audit trail requirements under 21 CFR Part 11 and SOX compliance.',
    `data_package_type` STRING COMMENT 'Type of regulatory data package submitted with the application. Full = complete standalone dossier (NCE/NBE); 505(b)(2) = hybrid relying on published literature or prior approvals; Hybrid = EU hybrid application; Bibliographic = based on published scientific literature. Determines applicable exclusivity type and duration.. Valid values are `full|505b2|hybrid|bibliographic`',
    `dmf_number` STRING COMMENT 'FDA Drug Master File (DMF) number associated with the drug substance or drug product covered by this exclusivity, where applicable. Supports CMC (Chemistry Manufacturing and Controls) linkage and regulatory audit.',
    `dosage_form` STRING COMMENT 'The pharmaceutical dosage form of the product covered by this exclusivity (e.g., tablet, capsule, injection, solution, patch). Relevant because exclusivity may be dosage-form specific.',
    `exclusivity_category` STRING COMMENT 'Broad category of the exclusivity period indicating whether it applies to a small molecule (NCE/NME), biologic (NBE), orphan drug designation, pediatric extension, or combination product.. Valid values are `small_molecule|biologic|orphan|pediatric|combination`',
    `exclusivity_code` STRING COMMENT 'Internally assigned unique alphanumeric code identifying this exclusivity period record, used for cross-system referencing and lifecycle management tracking.. Valid values are `^EXC-[A-Z0-9]{4,20}$`',
    `exclusivity_duration_months` STRING COMMENT 'Total duration of the exclusivity period expressed in months as granted by the regulatory authority (e.g., 84 months for US orphan drug, 120 months for EU orphan drug, 144 months for US biologics). Supports duration validation and comparison across jurisdictions.',
    `exclusivity_expiry_date` DATE COMMENT 'The date on which the regulatory exclusivity period expires, after which generic or biosimilar applicants may reference the innovator data. Critical for lifecycle management and generic/biosimilar entry defense planning.',
    `exclusivity_start_date` DATE COMMENT 'The date on which the regulatory exclusivity period commences, typically aligned with the date of first approval (NDA/BLA/MAA approval date) or orphan designation date depending on exclusivity type.',
    `exclusivity_status` STRING COMMENT 'Current lifecycle status of the exclusivity period. Active = currently in force; Expired = past expiry date; Withdrawn = voluntarily or involuntarily revoked by authority; Challenged = subject to legal or regulatory challenge; Pending = granted but not yet effective; Suspended = temporarily halted pending review.. Valid values are `active|expired|withdrawn|challenged|pending|suspended`',
    `exclusivity_type` STRING COMMENT 'Classification of the regulatory exclusivity type granted. NCE = New Chemical Entity (5 years US); ODE = Orphan Drug Exclusivity (7 years US / 10 years EU); PED = Pediatric Exclusivity Extension (6 months); DATA = Data Exclusivity for new indication (3 years US); BIOL = Biologics Exclusivity (12 years US); REMS = Risk Evaluation and Mitigation Strategy exclusivity. [ENUM-REF-CANDIDATE: NCE|ODE|PED|DATA|BIOL|REMS|NME|PATENT_LINKAGE — promote to reference product]. Valid values are `NCE|ODE|PED|DATA|BIOL|REMS`',
    `first_generic_entry_date` DATE COMMENT 'The projected or actual date on which the first generic (ANDA) or biosimilar (351(k) BLA) product may enter the market following expiry or challenge of this exclusivity. Used for lifecycle management, revenue forecasting, and LOE (Loss of Exclusivity) planning.',
    `granting_authority` STRING COMMENT 'Regulatory authority that granted this exclusivity period (e.g., FDA for US market, EMA for EU market, PMDA for Japan, MHRA for UK post-Brexit). Determines jurisdiction and applicable exclusivity rules. [ENUM-REF-CANDIDATE: FDA|EMA|PMDA|MHRA|NMPA|WHO|DEA — 7 candidates stripped; promote to reference product]',
    `indication` STRING COMMENT 'The specific disease or condition for which the product is approved and for which this exclusivity was granted. Particularly important for new indication (3-year data exclusivity) and orphan drug exclusivity where exclusivity is indication-specific.',
    `is_orphan_designated` BOOLEAN COMMENT 'Indicates whether the product holds an orphan drug designation from FDA (Orphan Drug Act) or EMA (Regulation EC 141/2000), which is a prerequisite for orphan drug exclusivity (ODE). Distinct from exclusivity_type as designation may exist without exclusivity being granted.',
    `last_updated_timestamp` TIMESTAMP COMMENT 'Timestamp of the most recent update to this exclusivity period record, supporting change tracking and audit trail requirements under 21 CFR Part 11 electronic records regulations.',
    `legal_counsel_notes` STRING COMMENT 'Free-text notes from legal counsel regarding this exclusivity period, including litigation strategy, challenge responses, and coordination with patent attorneys. Classified as confidential due to potential attorney-client privilege content.',
    `lifecycle_stage` STRING COMMENT 'Current lifecycle management stage of the product relative to this exclusivity period. Pre-Approval = exclusivity anticipated but not yet granted; Active Protection = exclusivity in force; LOE Watch = within 24 months of expiry requiring active monitoring; Post-Expiry = exclusivity has lapsed.. Valid values are `pre_approval|active_protection|loe_watch|post_expiry`',
    `loe_risk_level` STRING COMMENT 'Assessed risk level for Loss of Exclusivity (LOE) based on proximity to expiry, challenge status, and competitive pipeline. Critical for commercial lifecycle management and strategic planning.. Valid values are `low|medium|high|critical`',
    `orphan_designation_number` STRING COMMENT 'Official orphan drug designation number assigned by FDA (ODA) or EMA (EC Regulation 141/2000) when exclusivity_type is ODE. Required for orphan drug exclusivity validation and regulatory reporting.',
    `patent_linkage_flag` BOOLEAN COMMENT 'Indicates whether this exclusivity period is linked to a listed patent in the FDA Orange Book or equivalent patent register, enabling coordination between patent protection and regulatory exclusivity for lifecycle management.',
    `pediatric_extension_expiry_date` DATE COMMENT 'The adjusted expiry date reflecting the 6-month pediatric exclusivity extension, if granted. Null if pediatric_extension_granted is False.',
    `pediatric_extension_granted` BOOLEAN COMMENT 'Indicates whether a 6-month pediatric exclusivity extension (PED) has been granted under the Best Pharmaceuticals for Children Act (BPCA) or EU Paediatric Regulation, extending the base exclusivity or patent term by 6 months.',
    `regulatory_basis` STRING COMMENT 'The specific statutory or regulatory provision under which this exclusivity was granted (e.g., 21 CFR 314.108(b)(2) for NCE, Orphan Drug Act Section 527, BPCIA Section 7002, EU Regulation 141/2000 Article 8). Supports legal and regulatory audit trails.',
    `rems_required` BOOLEAN COMMENT 'Indicates whether a Risk Evaluation and Mitigation Strategy (REMS) is required as a condition of approval for this product, which may confer additional exclusivity protections or market access restrictions relevant to generic entry.',
    `route_of_administration` STRING COMMENT 'The route by which the drug product is administered (e.g., oral, intravenous, subcutaneous, topical). Exclusivity may be route-specific, particularly for new indication or new formulation exclusivity.',
    `source_system` STRING COMMENT 'The operational system of record from which this exclusivity period data was sourced (e.g., Veeva Vault RIM, FDA Orange Book feed, EMA EPAR, SAP S/4HANA). Supports data lineage and Silver layer provenance tracking in the Databricks Lakehouse.. Valid values are `veeva_rim|sap_s4hana|orange_book|epar|manual|rims`',
    `therapeutic_area` STRING COMMENT 'The therapeutic area or disease category associated with the approved indication (e.g., Oncology, Immunology, Rare Diseases, Neurology, Cardiovascular). Used for portfolio segmentation and LOE impact analysis by therapeutic area.',
    CONSTRAINT pk_exclusivity_period PRIMARY KEY(`exclusivity_period_id`)
) COMMENT 'Tracks all regulatory exclusivity periods granted to pharmaceutical products, distinct from patent protection. Covers orphan drug exclusivity (7 years US / 10 years EU), data exclusivity (5 years NCE / 3 years new indication), pediatric exclusivity extension (6 months), new chemical entity exclusivity, biologics exclusivity (12 years US), and REMS exclusivity. Captures exclusivity type, granting authority (FDA, EMA, PMDA), start date, expiry date, product reference, and associated NDA/BLA/MAA number. Critical for lifecycle management and generic/biosimilar entry defense.';

CREATE OR REPLACE TABLE `pharmaceuticals_ecm`.`intellectual`.`trademark` (
    `trademark_id` BIGINT COMMENT 'Unique system-generated identifier for each trademark registration record in the pharmaceutical intellectual property portfolio.',
    `country_id` BIGINT COMMENT 'Foreign key linking to masterdata.country. Business justification: Trademarks are registered by jurisdiction; required for brand protection strategy, market entry planning, and global brand portfolio management.',
    `legal_entity_id` BIGINT COMMENT 'Foreign key linking to masterdata.legal_entity. Business justification: Trademarks are registered to legal entities; required for brand ownership tracking, legal compliance, and M&A due diligence in pharmaceutical branding.',
    `licensing_agreement_id` BIGINT COMMENT 'Foreign key linking to intellectual.licensing_agreement. Business justification: trademark has licensing_flag (BOOLEAN) indicating the trademark is subject to a licensing arrangement. The governing licensing agreement is tracked in licensing_agreement, which covers all IP licensin',
    `atc_classification_id` BIGINT COMMENT 'Foreign key linking to masterdata.atc_classification. Business justification: Trademarks are associated with therapeutic categories; required for brand strategy, market positioning, and therapeutic area-specific brand portfolio management.',
    `cost_center_id` BIGINT COMMENT 'Foreign key linking to masterdata.cost_center. Business justification: Trademark maintenance costs (annuity fees, watch services, opposition proceedings) are tracked against cost centers for IP budget management and financial reporting. A pharma IP controller expects tra',
    `inn_registry_id` BIGINT COMMENT 'Foreign key linking to masterdata.inn_registry. Business justification: Trademarks are brand names for INN-based drugs. EMA and FDA require INN alongside brand name on packaging; regulatory submissions map trademark to INN. inn_name on trademark is a denormalized represen',
    `profit_center_id` BIGINT COMMENT 'Foreign key linking to masterdata.profit_center. Business justification: Trademarks are associated with profit centers for brand P&L reporting and licensing revenue attribution under IFRS. Brand management requires profit-center-level trademark portfolio reporting. No exis',
    `material_id` BIGINT COMMENT 'Foreign key linking to masterdata.material. Business justification: Brand trademarks are associated with specific materials (finished drug products) for packaging artwork management and supply chain labeling compliance. Artwork approval workflows require trademark-to-',
    `application_number` STRING COMMENT 'The official application number assigned by the trademark office at the time of filing, prior to registration. Used to track the application through examination and opposition proceedings.',
    `colour_claim` STRING COMMENT 'Description of any specific colour or colour combination claimed as a feature of the trademark (e.g., Pantone codes, RGB values, or textual colour descriptions). Relevant for figurative and combined marks where colour is a distinctive element.',
    `created_timestamp` TIMESTAMP COMMENT 'The timestamp when the trademark record was first created in the system. Supports audit trail requirements and data lineage tracking in the Databricks Silver Layer.',
    `disclaimer_text` STRING COMMENT 'Any disclaimer of exclusive rights to specific elements of the trademark (e.g., generic or descriptive terms within a combined mark) as required or accepted by the trademark office during examination.',
    `expiry_date` DATE COMMENT 'The date on which the current trademark registration term expires and renewal must be filed to maintain protection. Critical for lifecycle management and brand protection continuity.',
    `external_counsel_firm` STRING COMMENT 'Name of the external law firm or IP agent responsible for managing the trademark prosecution and maintenance in the relevant jurisdiction. Supports coordination with legal counsel on prosecution strategy and renewal deadlines.',
    `filing_date` DATE COMMENT 'The date on which the trademark application was officially filed with the relevant trademark office. Establishes priority date for the mark in the jurisdiction.',
    `goods_services_description` STRING COMMENT 'Detailed textual description of the goods and/or services covered by the trademark registration, as specified in the application. For pharmaceutical trademarks, typically describes the therapeutic area, dosage form, and indication of the drug product covered.',
    `internal_reference_code` STRING COMMENT 'Internal company reference code or docket number assigned to the trademark record in the companys IP management system (e.g., Veeva Vault RIM or internal IP docketing system). Enables cross-referencing with internal IP portfolio management tools.',
    `litigation_flag` BOOLEAN COMMENT 'Indicates whether the trademark is currently involved in active litigation or legal proceedings (True), such as infringement actions, cancellation proceedings, or inter partes disputes. Triggers coordination with legal counsel.',
    `madrid_international_number` STRING COMMENT 'The WIPO-assigned international registration number for trademarks filed under the Madrid Protocol. Populated only when madrid_protocol_flag is True.',
    `madrid_protocol_flag` BOOLEAN COMMENT 'Indicates whether this trademark registration was obtained through the WIPO Madrid Protocol international registration system (True) or through a direct national/regional filing (False). Affects renewal procedures and management workflows.',
    `mark_type` STRING COMMENT 'Classification of the trademark by its nature: word mark (text only), figurative mark (logo/image only), combined mark (text and image), three-dimensional mark (shape), sound mark, or colour mark. Drives brand protection strategy and enforcement scope. [ENUM-REF-CANDIDATE: word_mark|figurative_mark|combined_mark|three_dimensional_mark|sound_mark|colour_mark — promote to reference product]. Valid values are `word_mark|figurative_mark|combined_mark|three_dimensional_mark|sound_mark|colour_mark`',
    `nice_class_codes` STRING COMMENT 'Comma-separated list of Nice Classification class numbers (1–45) under which the trademark is registered. For pharmaceutical trademarks, typically includes Class 5 (pharmaceutical preparations) and potentially Class 10 (medical devices) or Class 44 (medical services). Defines the scope of goods and services covered by the mark.',
    `notes` STRING COMMENT 'Free-text field for capturing additional remarks, prosecution history notes, strategic comments, or legal observations relevant to the trademark record that are not captured in structured fields.',
    `office_code` STRING COMMENT 'Code identifying the trademark office or registry where the application was filed or registration is held (e.g., USPTO for United States, EUIPO for European Union, UKIPO for United Kingdom, JPO for Japan, CNIPA for China, WIPO for international registrations). [ENUM-REF-CANDIDATE: USPTO|EUIPO|UKIPO|JPO|CNIPA|WIPO|CIPO|IP_AUSTRALIA — promote to reference product]',
    `opposition_deadline_date` DATE COMMENT 'The date by which third parties may file an opposition to the trademark application in the relevant jurisdiction. Critical for monitoring the applications progress toward registration and for assessing third-party challenge risk.',
    `opposition_status` STRING COMMENT 'Current status of any opposition proceedings against the trademark application: not_opposed (no opposition filed), opposition_filed (third-party opposition pending), opposition_withdrawn (opponent withdrew), or opposition_decided (proceeding concluded by the trademark office).. Valid values are `not_opposed|opposition_filed|opposition_withdrawn|opposition_decided`',
    `owner_country_code` STRING COMMENT 'ISO 3166-1 alpha-3 country code of the trademark owners country of domicile or incorporation, as recorded in the trademark register.. Valid values are `^[A-Z]{3}$`',
    `priority_claim_country_code` STRING COMMENT 'ISO 3166-1 alpha-3 country code of the jurisdiction in which the priority application was originally filed, as claimed under the Paris Convention.. Valid values are `^[A-Z]{3}$`',
    `priority_claim_date` DATE COMMENT 'The date of the earliest priority application claimed under the Paris Convention, if the trademark application claims priority from a prior filing in another jurisdiction. Establishes the effective priority date for multi-jurisdictional filings.',
    `product_launch_country_code` STRING COMMENT 'ISO 3166-1 alpha-3 country code of the primary market where the associated pharmaceutical drug product is commercially launched or planned for launch under this trademark. Links trademark protection to commercial launch activities.. Valid values are `^[A-Z]{3}$`',
    `registration_date` DATE COMMENT 'The date on which the trademark was officially registered by the trademark office. Marks the start of the initial registration term and triggers renewal obligation tracking.',
    `registration_number` STRING COMMENT 'The official registration number assigned by the trademark office upon successful registration of the mark. Serves as the externally-known unique identifier for the trademark in the relevant jurisdiction.',
    `registration_status` STRING COMMENT 'Current lifecycle status of the trademark registration: pending (application filed, under examination), registered (officially granted), opposed (subject to third-party opposition proceedings), cancelled (registration revoked), expired (lapsed due to non-renewal), or abandoned (application withdrawn or lapsed). Critical for brand protection and commercial launch readiness.. Valid values are `pending|registered|opposed|cancelled|expired|abandoned`',
    `renewal_date` DATE COMMENT 'The date by which the renewal application must be submitted to the trademark office to avoid lapse of the registration. May differ from expiry_date due to grace period provisions.',
    `renewal_reminder_date` DATE COMMENT 'The internal reminder date set for initiating the trademark renewal process, typically set a defined number of months before the official renewal_date. Supports proactive renewal management and avoidance of unintentional lapse.',
    `therapeutic_area` STRING COMMENT 'The therapeutic area or disease category for which the associated drug product is indicated (e.g., Oncology, Immunology, Rare Diseases, Cardiovascular). Supports portfolio segmentation and brand strategy analytics.',
    `trademark_name` STRING COMMENT 'The brand name, word mark, or slogan that is the subject of the trademark registration (e.g., a proprietary drug brand name). Serves as the primary human-readable identity label for the trademark record.',
    `updated_timestamp` TIMESTAMP COMMENT 'The timestamp when the trademark record was last modified in the system. Supports audit trail requirements, change tracking, and incremental data processing in the Databricks Silver Layer.',
    `use_anywhere_date` DATE COMMENT 'The date on which the trademark was first used anywhere (not necessarily in commerce) in connection with the identified goods/services. Relevant for establishing priority in use-based trademark systems.',
    `use_in_commerce_date` DATE COMMENT 'The date on which the trademark was first used in commerce in connection with the goods/services identified in the registration. Required for use-based trademark systems (e.g., USPTO) and relevant for establishing priority and defending against cancellation for non-use.',
    `watch_service_flag` BOOLEAN COMMENT 'Indicates whether a trademark watch service is active for this mark (True), monitoring for conflicting third-party applications in the relevant jurisdictions. Supports proactive brand protection strategy.',
    CONSTRAINT pk_trademark PRIMARY KEY(`trademark_id`)
) COMMENT 'Master record for all pharmaceutical trademark registrations including brand names, logos, trade dress, and slogans. Captures trademark name, registration number, filing date, registration date, expiry/renewal date, jurisdiction, Nice classification, goods and services description, trademark type (word mark, figurative, combined), owner entity, and current status (pending, registered, opposed, cancelled). Supports brand protection strategy and commercial launch activities.';

CREATE OR REPLACE TABLE `pharmaceuticals_ecm`.`intellectual`.`drug_master_file` (
    `drug_master_file_id` BIGINT COMMENT 'Unique surrogate identifier for the Drug Master File record in the enterprise data platform (Silver Layer). Primary key for this entity.',
    `country_id` BIGINT COMMENT 'Foreign key linking to masterdata.country. Business justification: DMFs are filed with country-specific regulatory authorities; required for regulatory compliance, supply chain qualification, and market-specific manufacturing authorization.',
    `legal_entity_id` BIGINT COMMENT 'Foreign key linking to masterdata.legal_entity. Business justification: DMFs are held by legal entities; required for regulatory submissions, supply chain qualification, and vendor management in pharmaceutical manufacturing.',
    `licensing_agreement_id` BIGINT COMMENT 'Foreign key linking to intellectual.licensing_agreement. Business justification: Drug Master Files (DMFs) contain confidential manufacturing and formulation information. DMF holders often grant access to third parties (e.g., generic manufacturers, partners) via licensing agreement',
    `atc_classification_id` BIGINT COMMENT 'Foreign key linking to masterdata.atc_classification. Business justification: DMFs are classified by ATC for regulatory portfolio management and therapeutic area reporting. atc_code on drug_master_file is a denormalized representation of atc_classification.atc_code. Proper FK e',
    `cost_center_id` BIGINT COMMENT 'Foreign key linking to masterdata.cost_center. Business justification: DMF maintenance costs (annual updates, regulatory submissions, amendment fees) are tracked against cost centers for regulatory affairs budget management and R&D cost capitalization under IAS 38. No ex',
    `inn_registry_id` BIGINT COMMENT 'Foreign key linking to masterdata.inn_registry. Business justification: DMFs describe specific INNs; required for regulatory submissions, molecule-DMF linkage, and supply chain qualification in pharmaceutical manufacturing.',
    `profit_center_id` BIGINT COMMENT 'Foreign key linking to masterdata.profit_center. Business justification: DMFs support commercial products; their costs and associated revenues are attributed to profit centers for product P&L reporting and segment financial reporting. No existing profit_center FK on drug_m',
    `material_id` BIGINT COMMENT 'Foreign key linking to masterdata.material. Business justification: DMFs describe specific materials; required for regulatory compliance, procurement, and material-DMF linkage in pharmaceutical supply chain management.',
    `plant_id` BIGINT COMMENT 'Foreign key linking to masterdata.plant. Business justification: DMFs reference manufacturing sites; essential for regulatory submissions, supply chain qualification, and site-specific manufacturing authorization.',
    `api_manufacturer_flag` BOOLEAN COMMENT 'Indicates whether the DMF holder is the manufacturer of the Active Pharmaceutical Ingredient (API) covered by this DMF. True for Type II DMFs where the holder manufactures the drug substance. Used to distinguish API manufacturers from intermediates suppliers, excipient suppliers, and packaging material suppliers.',
    `cas_number` STRING COMMENT 'CAS Registry Number uniquely identifying the chemical substance covered by the DMF. Used for substance identification in regulatory submissions, safety databases, and supply chain qualification. Applicable primarily to Type II (API/DS) and Type IV (excipient) DMFs.. Valid values are `^[0-9]{2,7}-[0-9]{2}-[0-9]$`',
    `cmc_section_reference` STRING COMMENT 'Reference to the specific CMC (Chemistry, Manufacturing, and Controls) section of the eCTD submission (Module 3) that this DMF supports. Used to map the DMF to the corresponding regulatory dossier section for NDA/BLA/ANDA/MAA submissions.',
    `confidentiality_commitment_date` DATE COMMENT 'Date on which the regulatory authority acknowledged the confidential nature of the DMF content. The FDA treats DMF content as confidential trade secret information. This date records when the confidentiality commitment was formally established, supporting IP protection and trade secret management.',
    `created_timestamp` TIMESTAMP COMMENT 'Timestamp when this DMF record was first created in the enterprise data platform. Used for audit trail, data lineage, and compliance with 21 CFR Part 11 electronic records requirements.',
    `cross_reference_count` STRING COMMENT 'Number of active regulatory applications (NDA, BLA, ANDA, IND, MAA) that currently cross-reference this DMF. Indicates the commercial and regulatory criticality of the DMF; a high count signals high supply chain dependency and elevated risk if the DMF is withdrawn or goes inactive.',
    `dmf_number` STRING COMMENT 'Official DMF number assigned by the regulatory authority (e.g., FDA) upon receipt of the DMF submission. Serves as the primary external identifier used in cross-references within NDA, BLA, ANDA, and IND applications. Format varies by authority (e.g., FDA assigns a numeric DMF number).',
    `dmf_status` STRING COMMENT 'Current lifecycle status of the DMF with the regulatory authority. active indicates the DMF is in good standing and available for cross-reference; inactive indicates it has not been updated within the required period; withdrawn indicates the holder has formally withdrawn the file; under_review indicates a pending agency review; closed indicates the file has been administratively closed.. Valid values are `active|inactive|withdrawn|under_review|closed`',
    `dmf_type` STRING COMMENT 'Classification of the DMF per FDA categorization: Type I (Manufacturing Site, Facilities, Operating Procedures, and Personnel — discontinued by FDA but retained for legacy), Type II (Drug Substance, Drug Substance Intermediate, and Material Used in Their Preparation, or Drug Product), Type III (Packaging Material), Type IV (Excipient, Colorant, Flavor, Essence, or Material Used in Their Preparation), Type V (FDA-Accepted Reference Information). Drives CMC submission strategy and third-party qualification workflows.. Valid values are `Type I|Type II|Type III|Type IV|Type V`',
    `dosage_form` STRING COMMENT 'Physical form of the drug product or substance covered by the DMF (e.g., tablet, capsule, injectable solution, lyophilized powder, cream, patch). Relevant primarily for Type II (Drug Product) and Type III (Packaging) DMFs. Aligns with FDA/EMA dosage form terminology. [ENUM-REF-CANDIDATE: tablet|capsule|injectable_solution|lyophilized_powder|cream|patch|suspension|gel|suppository|inhalation_powder — promote to reference product]',
    `ectd_sequence_number` STRING COMMENT 'Four-digit eCTD sequence number assigned to the DMF submission or amendment within the eCTD lifecycle. Used to track the submission history and version control of the DMF in the regulatory authoritys electronic submission gateway.. Valid values are `^[0-9]{4}$`',
    `effective_date` DATE COMMENT 'Date on which the DMF became effective and available for cross-reference by applicants in regulatory submissions (NDA, BLA, ANDA, IND). May differ from submission date if the authority requires a review period before the file is deemed active.',
    `fda_establishment_identifier` STRING COMMENT 'FDA Establishment Identifier (FEI) number assigned to the manufacturing facility by the FDA. Used to link the DMF to the FDAs establishment registration database, enabling GMP inspection history lookup and import alert monitoring.',
    `gmp_certificate_expiry_date` DATE COMMENT 'Expiry date of the current GMP certificate for the manufacturing site associated with this DMF. Triggers renewal workflows and supplier qualification reviews. An expired GMP certificate may block use of the DMF in new regulatory submissions.',
    `gmp_certificate_number` STRING COMMENT 'Certificate number of the current GMP certificate issued by a recognized regulatory authority or inspection body (e.g., FDA, EMA, PIC/S member authority) for the manufacturing site associated with this DMF. Used for supplier qualification and regulatory compliance verification.',
    `last_amendment_date` DATE COMMENT 'Date of the most recent amendment or annual update submitted to the regulatory authority for this DMF. FDA requires annual updates to maintain active status. Tracks currency of the file and triggers compliance alerts when updates are overdue.',
    `letter_of_authorization_date` DATE COMMENT 'Date on which the DMF holder issued the Letter of Authorization (LOA) permitting the company to cross-reference this DMF in its regulatory submissions. Relevant when the company is the applicant referencing a third-party DMF.',
    `letter_of_authorization_required` BOOLEAN COMMENT 'Indicates whether a Letter of Authorization (LOA) from the DMF holder is required before an applicant can cross-reference this DMF in their regulatory submission. True for most Type II and Type IV DMFs where the holder controls access to confidential manufacturing information.',
    `manufacturing_site_country_code` STRING COMMENT 'ISO 3166-1 alpha-3 country code for the country where the manufacturing site is located. Used for import/export compliance, country-of-origin tracking, supply chain risk management, and regulatory jurisdiction determination.. Valid values are `^[A-Z]{3}$`',
    `next_annual_update_due_date` DATE COMMENT 'Calculated due date for the next mandatory annual update submission to maintain active DMF status with the regulatory authority. Derived from the last amendment date plus 12 months. Used for compliance monitoring and proactive submission planning.',
    `notes` STRING COMMENT 'Free-text field for capturing additional regulatory, operational, or strategic notes related to this DMF. May include information about pending amendments, agency correspondence, supplier negotiations, or lifecycle management decisions not captured in structured fields.',
    `proprietary_holder_flag` BOOLEAN COMMENT 'Indicates whether the company itself (Pharmaceuticals) is the holder of this DMF (True) or whether it is a third-party supplier DMF that the company cross-references (False). Drives different workflows: internal DMFs require internal maintenance; third-party DMFs require supplier management and LOA tracking.',
    `regulatory_authority` STRING COMMENT 'The regulatory authority to which the DMF was submitted (e.g., FDA for US, EMA for EU, PMDA for Japan, MHRA for UK, NMPA for China). Determines applicable regulatory requirements, format standards (e.g., eCTD vs. paper), and review timelines. [ENUM-REF-CANDIDATE: FDA|EMA|PMDA|MHRA|NMPA|WHO|Health Canada|TGA — 8 candidates stripped; promote to reference product]',
    `rims_tracking_number` STRING COMMENT 'Internal tracking number assigned to this DMF record within the companys Regulatory Information Management System (RIMS), such as Veeva Vault RIM. Used for internal workflow management, submission tracking, and audit trail purposes.',
    `route_of_administration` STRING COMMENT 'Intended route of administration for the drug substance or product covered by the DMF (e.g., oral, intravenous, subcutaneous, topical, inhalation). Applicable for Type II DMFs. Aligns with FDA/EMA route of administration terminology. [ENUM-REF-CANDIDATE: oral|intravenous|subcutaneous|intramuscular|topical|inhalation|transdermal|intrathecal — promote to reference product]',
    `submission_date` DATE COMMENT 'Date on which the DMF was first submitted to the regulatory authority. Establishes the official filing date and is used to calculate review timelines, annual update obligations, and IP/exclusivity period calculations.',
    `submission_format` STRING COMMENT 'Format in which the DMF was submitted to the regulatory authority: eCTD (Electronic Common Technical Document — mandatory for FDA since 2017 for most submissions), paper (legacy paper-based submission), or NeeS (Non-eCTD Electronic Submission — used in some jurisdictions). Determines document management and archival requirements.. Valid values are `eCTD|paper|NeeS`',
    `therapeutic_area` STRING COMMENT 'Primary therapeutic area or disease indication associated with the drug substance covered by this DMF (e.g., Oncology, Immunology, Rare Diseases, Cardiovascular, Neurology). Used for portfolio management, lifecycle planning, and IP strategy alignment. [ENUM-REF-CANDIDATE: oncology|immunology|rare_diseases|cardiovascular|neurology|infectious_diseases|metabolic|respiratory|dermatology|hematology — promote to reference product]',
    `title` STRING COMMENT 'Official descriptive title of the DMF as submitted to the regulatory authority. Typically includes the substance or material name, manufacturer name, and scope of the file (e.g., Drug Substance DMF for [INN] manufactured at [Site]).',
    `updated_timestamp` TIMESTAMP COMMENT 'Timestamp when this DMF record was most recently updated in the enterprise data platform. Used for change tracking, audit trail, and data freshness monitoring in compliance with 21 CFR Part 11.',
    `veeva_vault_document_reference` STRING COMMENT 'Document identifier in Veeva Vault RIM (Regulatory Information Management) system where the DMF submission package and associated correspondence are stored. Enables traceability between the enterprise data platform record and the source regulatory document management system.',
    `withdrawal_date` DATE COMMENT 'Date on which the DMF holder formally withdrew the DMF from the regulatory authority. Populated only when dmf_status is withdrawn. Triggers downstream impact assessment for any NDA/BLA/ANDA applications that cross-reference this DMF.',
    CONSTRAINT pk_drug_master_file PRIMARY KEY(`drug_master_file_id`)
) COMMENT 'Master record for Drug Master Files (DMFs) submitted to regulatory authorities. Covers Type I-V DMFs (manufacturing site, drug substance/API, packaging, excipient, reference information). Captures DMF number, type, holder, submission/amendment dates, regulatory authority, active status, and associated substance. Supports CMC submissions and third-party API/excipient qualification for regulatory filings.';

CREATE OR REPLACE TABLE `pharmaceuticals_ecm`.`intellectual`.`licensing_agreement` (
    `licensing_agreement_id` BIGINT COMMENT 'Unique surrogate identifier for the licensing agreement record in the intellectual property portfolio system.',
    `business_partner_id` BIGINT COMMENT 'Foreign key linking to masterdata.business_partner. Business justification: The licensee in a licensing agreement is a business partner in the vendor/customer master. Linking enables royalty payment processing, credit management, and partner relationship management. licensee_',
    `legal_entity_id` BIGINT COMMENT 'Foreign key linking to masterdata.legal_entity. Business justification: Licensing agreements require tracking licensor legal entity for contract management, revenue recognition, and intercompany royalty accounting in pharmaceutical partnerships.',
    `atc_classification_id` BIGINT COMMENT 'Foreign key linking to masterdata.atc_classification. Business justification: Licensing portfolio is segmented by ATC therapeutic class for business development reporting, deal valuation, and portfolio strategy. BD teams report licensing deal value by therapeutic area using ATC',
    `cost_center_id` BIGINT COMMENT 'Foreign key linking to masterdata.cost_center. Business justification: License agreements generate costs/revenues allocated to cost centers; required for P&L reporting, royalty expense tracking, and business unit accountability.',
    `inn_registry_id` BIGINT COMMENT 'Foreign key linking to masterdata.inn_registry. Business justification: Licensing agreements for pharmaceutical compounds are tied to specific INNs (active substances). Royalty calculation, FTO analysis, and regulatory compliance tracking require substance-level licensing',
    `profit_center_id` BIGINT COMMENT 'Foreign key linking to masterdata.profit_center. Business justification: License agreements are assigned to business segments; required for revenue recognition, segment P&L reporting, and royalty income allocation.',
    `country_id` BIGINT COMMENT 'Foreign key linking to masterdata.country. Business justification: License territories define geographic scope; essential for revenue allocation, royalty calculation, and compliance with territorial restrictions in pharmaceutical licensing.',
    `agreement_number` STRING COMMENT 'Externally-known, human-readable reference number assigned to the licensing agreement, used in correspondence with counterparties, legal counsel, and regulatory filings. Serves as the BUSINESS_IDENTIFIER for this MASTER_AGREEMENT entity.',
    `agreement_status` STRING COMMENT 'Current lifecycle state of the licensing agreement. Draft: under negotiation. Active: fully executed and in force. Suspended: temporarily paused by mutual consent or breach notice. Terminated: ended before natural expiry. Expired: reached end of term without renewal. Drives deal management workflows and financial reporting.. Valid values are `draft|active|suspended|terminated|expired`',
    `agreement_type` STRING COMMENT 'Classification of the licensing agreement by deal structure. In-licensing: rights acquired from a third party. Out-licensing: rights granted to a third party. Cross-licensing: mutual exchange of IP rights. Co-development: joint development with shared IP. Collaboration: broad research or commercialization partnership. Drives revenue recognition treatment under ASC 606.. Valid values are `in-licensing|out-licensing|cross-licensing|co-development|collaboration`',
    `change_of_control_provision` BOOLEAN COMMENT 'Indicates whether the agreement contains a change-of-control clause that grants termination or renegotiation rights upon acquisition or merger of either party. True = change-of-control provision exists; False = no such provision. Critical for M&A due diligence and IP portfolio valuation.',
    `commercial_milestone_value` DECIMAL(18,2) COMMENT 'Aggregate value of all commercial milestone payments (e.g., first commercial sale, annual net sales thresholds) defined in the agreement, expressed in the agreement currency. Supports commercial launch planning and ASC 606 variable consideration estimation.',
    `created_timestamp` TIMESTAMP COMMENT 'Timestamp when the licensing agreement record was first created in the system, in ISO 8601 format (yyyy-MM-ddTHH:mm:ss.SSSXXX). Provides the RECORD_AUDIT_CREATED audit trail required for 21 CFR Part 11 compliance and SOX financial reporting controls.',
    `currency_code` STRING COMMENT 'ISO 4217 three-letter currency code in which all financial obligations under the agreement (upfront payments, milestones, royalties) are denominated (e.g., USD, EUR, JPY, GBP). Required for multi-currency royalty accounting and foreign exchange hedging.. Valid values are `^[A-Z]{3}$`',
    `development_milestone_value` DECIMAL(18,2) COMMENT 'Aggregate value of all development-stage milestone payments (e.g., IND submission, Phase I/II/III completion) defined in the agreement, expressed in the agreement currency. Supports clinical development budget planning and ASC 606 variable consideration estimation.',
    `diligence_obligations` STRING COMMENT 'Narrative description of the commercially reasonable efforts or best efforts diligence obligations imposed on the licensee to develop and commercialize the licensed product. Failure to meet diligence obligations may trigger termination rights. Used for partner relationship management and compliance monitoring.',
    `dispute_resolution_mechanism` STRING COMMENT 'Contractually agreed mechanism for resolving disputes between the parties. Arbitration: binding arbitration under specified rules (e.g., ICC, AAA). Litigation: resolution through courts of the governing jurisdiction. Mediation: non-binding mediation before escalation. Expert-determination: technical disputes resolved by independent expert.. Valid values are `arbitration|litigation|mediation|expert-determination`',
    `effective_date` DATE COMMENT 'Date on which the licensing agreement becomes legally binding and operative. Marks the start of the agreement term for royalty accrual, exclusivity period calculation, and milestone tracking. Corresponds to EFFECTIVE_FROM for the MASTER_AGREEMENT role.',
    `exclusivity_type` STRING COMMENT 'Scope of exclusivity granted under the license. Exclusive: licensee is the sole permitted user in the territory/field. Non-exclusive: licensor may grant same rights to others. Co-exclusive: limited number of licensees permitted. Semi-exclusive: licensor retains right to practice but not to license others. Critical for generic/biosimilar entry defense strategy.. Valid values are `exclusive|non-exclusive|co-exclusive|semi-exclusive`',
    `execution_date` DATE COMMENT 'Date on which the licensing agreement was formally signed and executed by all parties. May differ from the effective date if the agreement has a retroactive or future effective date. Used for legal record-keeping and audit trails.',
    `expiry_date` DATE COMMENT 'Date on which the licensing agreement naturally expires at the end of its agreed term. Nullable for perpetual or open-ended agreements. Drives lifecycle management alerts, renewal negotiations, and IP exclusivity planning. Corresponds to EFFECTIVE_UNTIL for the MASTER_AGREEMENT role.',
    `field_of_use` STRING COMMENT 'Specific therapeutic area, indication, or application domain within which the licensee is permitted to use the licensed IP. Examples: oncology, rare diseases, human therapeutics only, diagnostic use. Restricts the scope of the license and is critical for exclusivity analysis and sublicensing rights management.',
    `governing_law` STRING COMMENT 'ISO 3166-1 alpha-3 country code of the jurisdiction whose laws govern the interpretation and enforcement of the agreement. Determines applicable contract law, dispute resolution procedures, and regulatory compliance obligations.. Valid values are `^[A-Z]{3}$`',
    `last_updated_timestamp` TIMESTAMP COMMENT 'Timestamp when the licensing agreement record was most recently modified, in ISO 8601 format (yyyy-MM-ddTHH:mm:ss.SSSXXX). Provides the RECORD_AUDIT_UPDATED audit trail required for 21 CFR Part 11 compliance and change control tracking.',
    `legal_counsel_reference` STRING COMMENT 'Name or identifier of the internal or external legal counsel responsible for drafting, negotiating, and maintaining the agreement. Used for coordination on patent litigation, IP enforcement, and contract amendments.',
    `licensed_asset_description` STRING COMMENT 'Narrative description of the intellectual property assets covered by the license, including compound names (INN/USAN), patent numbers, know-how, trade secrets, trademarks, or biological sequences. Supports IP portfolio management and freedom-to-operate analysis.',
    `licensed_asset_type` STRING COMMENT 'Classification of the primary intellectual property asset type covered by the agreement. Patent: granted patent rights. Know-how: proprietary technical knowledge. Trademark: brand or trade name rights. Data-package: regulatory data exclusivity or clinical data. Biological-sequence: gene or protein sequence rights. Trade-secret: confidential proprietary information. [ENUM-REF-CANDIDATE: patent|know-how|trademark|data-package|biological-sequence|trade-secret|formulation|process — promote to reference product]. Valid values are `patent|know-how|trademark|data-package|biological-sequence|trade-secret`',
    `milestone_count` STRING COMMENT 'Total number of contractually defined milestone events (development, regulatory, and commercial) specified in the agreement. Used for milestone tracking dashboards, deal management reporting, and ASC 606 performance obligation identification.',
    `regulatory_milestone_value` DECIMAL(18,2) COMMENT 'Aggregate value of all regulatory milestone payments (e.g., NDA/BLA/MAA submission, FDA/EMA approval) defined in the agreement, expressed in the agreement currency. Supports regulatory affairs planning and ASC 606 variable consideration estimation.',
    `responsible_party` STRING COMMENT 'Identifies which party bears primary responsibility for conducting development activities (clinical trials, regulatory submissions, manufacturing scale-up) under the agreement. Licensor: licensor retains development responsibility. Licensee: licensee assumes development responsibility. Joint: shared responsibility as defined in the agreement.. Valid values are `licensor|licensee|joint`',
    `right_of_first_negotiation` BOOLEAN COMMENT 'Indicates whether the agreement grants either party a right of first negotiation (ROFN) for additional territories, indications, or follow-on compounds. True = ROFN exists; False = no ROFN. Relevant for lifecycle management and business development strategy.',
    `royalty_base` STRING COMMENT 'The contractual basis on which royalties are calculated. Net-sales: royalties applied to net sales after standard deductions. Gross-sales: royalties applied to gross sales before deductions. Net-revenue: royalties applied to net revenue. Units-sold: royalties calculated per unit sold. Determines the royalty accounting methodology.. Valid values are `net-sales|gross-sales|net-revenue|units-sold`',
    `royalty_rate` DECIMAL(18,2) COMMENT 'Contractual royalty rate expressed as a decimal fraction of net sales (e.g., 0.050000 = 5.0%) payable by the licensee to the licensor. Used for royalty accrual calculations, revenue recognition under ASC 606/IFRS 15, and P&L forecasting. Null if the agreement uses a tiered royalty structure captured in a separate milestone/royalty schedule.',
    `sap_contract_number` STRING COMMENT 'Contract number assigned in SAP S/4HANA (SD or FI module) for financial processing of royalty payments, milestone invoicing, and upfront fee recognition. Enables reconciliation between the IP portfolio system and the ERP for royalty accounting and revenue recognition.',
    `sublicensing_permitted` BOOLEAN COMMENT 'Indicates whether the licensee has the contractual right to sublicense the licensed IP to third parties (e.g., CMOs, CDMOs, or sub-distributors). True = sublicensing permitted; False = sublicensing prohibited. Impacts CMO/CDMO engagement and supply chain structuring.',
    `termination_conditions` STRING COMMENT 'Summary of the contractual conditions under which either party may terminate the agreement, including material breach cure periods, insolvency triggers, regulatory failure events, and convenience termination rights. Used by legal counsel for contract management and risk assessment.',
    `termination_date` DATE COMMENT 'Date on which the licensing agreement was terminated prior to its natural expiry, whether by mutual consent, breach, or exercise of termination rights. Null if the agreement has not been terminated. Used for financial close-out and IP rights reversion tracking.',
    `total_deal_value` DECIMAL(18,2) COMMENT 'Total potential deal value including upfront payments, all milestone payments, and estimated royalties over the agreement term, expressed in the agreement currency. Used for deal valuation, P&L forecasting, and investor disclosure. Represents the gross deal value before probability-weighting.',
    `total_milestone_value` DECIMAL(18,2) COMMENT 'Sum of all contractually defined milestone payment amounts across all milestone events in the agreement, expressed in the agreement currency. Represents the maximum milestone-based consideration achievable under the agreement. Used for deal valuation and revenue recognition planning.',
    `upfront_payment_amount` DECIMAL(18,2) COMMENT 'One-time upfront license fee or signing payment due at execution of the agreement, expressed in the agreement currency. Recognized as revenue or capitalized as an intangible asset depending on the nature of the license under ASC 606/IFRS 15. Part of the MONETARY_TRIPLET for this MASTER_AGREEMENT.',
    `veeva_vault_document_reference` STRING COMMENT 'Reference identifier of the fully executed agreement document stored in Veeva Vault (RIM or QualityDocs module). Enables direct navigation from the data product record to the source legal document for audit, due diligence, and regulatory inspection purposes. Aligns with 21 CFR Part 11 electronic records requirements.',
    CONSTRAINT pk_licensing_agreement PRIMARY KEY(`licensing_agreement_id`)
) COMMENT 'Records all IP licensing agreements (in-licensing, out-licensing, cross-licensing, co-development, collaboration) including deal terms, milestone obligations, and milestone payment tracking. Captures agreement type, parties, licensed assets, territory, field of use, exclusivity scope, royalty structure, milestone events (regulatory filing, IND submission, phase completion, NDA approval, first commercial sale, sales thresholds), milestone descriptions, trigger events, milestone due dates, achieved dates, milestone payment amounts, currency, payment status, responsible party, sublicensing rights, and termination conditions. Supports deal management, milestone tracking, revenue recognition (ASC 606), royalty accounting, and partner relationship management.';

CREATE OR REPLACE TABLE `pharmaceuticals_ecm`.`intellectual`.`royalty_payment` (
    `royalty_payment_id` BIGINT COMMENT 'Unique system-generated identifier for each royalty payment transaction record within the intellectual property portfolio management system.',
    `drug_product_id` BIGINT COMMENT 'Foreign key linking to product.drug_product. Business justification: Royalty payments are calculated on net sales of specific drug products (by dosage form and strength). Finance and BD teams need drug_product-level granularity for royalty reporting, audit reconciliati',
    `journal_entry_id` BIGINT COMMENT 'Foreign key linking to finance.journal_entry. Business justification: Every royalty payment (in or out) generates a GL posting for revenue/expense recognition. Finance links royalty payments to journal entries for reconciliation, audit trail, SOX compliance, and revenue',
    `licensing_agreement_id` BIGINT COMMENT 'Reference to the licensing agreement under which this royalty payment is made or received. Links the payment to the governing contract terms.',
    `cost_center_id` BIGINT COMMENT 'Foreign key linking to masterdata.cost_center. Business justification: Royalty payments are posted to cost centers for financial controlling and budget variance analysis. cost_center_code on royalty_payment is a denormalized representation of cost_center.cost_center_code',
    `profit_center_id` BIGINT COMMENT 'Foreign key linking to masterdata.profit_center. Business justification: Royalty payments are attributed to profit centers for product P&L reporting and segment financial reporting under IFRS 15 revenue recognition. Finance requires profit-center-level royalty income/expen',
    `medicinal_product_id` BIGINT COMMENT 'Foreign key linking to product.medicinal_product. Business justification: Royalty payments calculated on product-specific net sales. Essential for financial reporting, deal reconciliation, and product-level P&L attribution. Removes denormalized licensed_product_name.',
    `patent_id` BIGINT COMMENT 'Reference to the patent or intellectual property asset (NCE, NBE, formulation, or process patent) that is the subject of the royalty-bearing license.',
    `payment_run_id` BIGINT COMMENT 'Foreign key linking to finance.payment_run. Business justification: Royalty disbursements are executed via treasury payment runs. Linking royalty_payment to payment_run enables reconciliation of IP royalty payments against bank payment batches — required for treasury ',
    `business_partner_id` BIGINT COMMENT 'Reference to the party granting the license (the entity receiving royalty payments in an outbound scenario or paying in an inbound scenario).',
    `royalty_agreement_id` BIGINT COMMENT 'Foreign key linking to finance.royalty_agreement. Business justification: Royalty payments are calculated under a specific finance royalty_agreement governing rates, tiers, and territory. This FK enables royalty accounting reconciliation, audit trail, and rate-tier validati',
    `adjustment_amount` DECIMAL(18,2) COMMENT 'Any adjustments applied to the calculated royalty amount, such as corrections from prior period reconciliations, audit findings, or contractual true-ups. Positive values increase the payment; negative values reduce it.',
    `audit_flag` BOOLEAN COMMENT 'Indicates whether this royalty payment record has been flagged for formal royalty audit review, typically triggered by discrepancies between reported sales and expected royalty amounts or by contractual audit rights.',
    `bank_reference_number` STRING COMMENT 'Bank-issued transaction reference number or wire transfer confirmation number associated with the royalty payment. Used for bank reconciliation and payment verification.',
    `calculation_period_end_date` DATE COMMENT 'End date of the royalty calculation period for which net sales or units sold are being reported and royalties computed. Together with start date defines the reporting window per the licensing agreement.',
    `calculation_period_start_date` DATE COMMENT 'Start date of the royalty calculation period (e.g., quarter or year) for which net sales or units sold are being reported and royalties computed. Aligns with licensing agreement reporting obligations.',
    `created_timestamp` TIMESTAMP COMMENT 'Timestamp when this royalty payment record was first created in the system. Supports audit trail requirements under SOX and 21 CFR Part 11 electronic records compliance.',
    `currency_code` STRING COMMENT 'Three-letter ISO 4217 currency code for the royalty payment transaction (e.g., USD, EUR, JPY). Determines the denomination of all monetary amounts in this record.. Valid values are `^[A-Z]{3}$`',
    `deductions_amount` DECIMAL(18,2) COMMENT 'Total allowable deductions applied to gross sales to arrive at net sales, as defined in the licensing agreement. Typically includes chargebacks, rebates, returns, freight, and applicable taxes.',
    `dispute_reason` STRING COMMENT 'Free-text description of the reason for disputing the royalty payment amount, applicable when payment_status is disputed. Documents the basis for disagreement between licensor and licensee for legal and audit purposes.',
    `due_date` DATE COMMENT 'Contractual deadline by which the royalty payment must be made as specified in the licensing agreement. Used to track overdue payments and trigger escalation workflows.',
    `exchange_rate` DECIMAL(18,2) COMMENT 'Foreign exchange rate applied to convert the transaction currency to the companys functional reporting currency at the time of payment. Required for multi-currency licensing agreements and consolidated financial reporting.',
    `functional_currency_amount` DECIMAL(18,2) COMMENT 'Total payment amount converted to the companys functional reporting currency using the applicable exchange rate. Used for consolidated P&L reporting and SOX financial controls.',
    `gl_account_code` STRING COMMENT 'SAP General Ledger account code to which this royalty payment is posted for financial reporting purposes. Distinguishes royalty income (inbound) from royalty expense (outbound) in the P&L.',
    `gross_sales_amount` DECIMAL(18,2) COMMENT 'Total gross sales revenue generated from the licensed product during the calculation period, before any deductions. Used as the starting point for net sales calculation per the licensing agreement definition.',
    `licensed_territory` STRING COMMENT 'Geographic territory or market for which the royalty payment applies, as defined in the licensing agreement. May be a country code (ISO 3166-1 alpha-3), region, or GLOBAL. Supports territory-level royalty analytics.',
    `minimum_royalty_amount` DECIMAL(18,2) COMMENT 'Contractual minimum royalty amount guaranteed per period as specified in the licensing agreement, regardless of actual sales performance. Applicable when the calculated royalty falls below this floor.',
    `net_sales_amount` DECIMAL(18,2) COMMENT 'Net sales revenue for the licensed product during the calculation period, calculated as gross sales minus allowable deductions per the licensing agreement definition. Forms the royalty basis for net-sales-based agreements.',
    `payment_date` DATE COMMENT 'The actual date on which the royalty payment was executed (funds transferred or received). Represents the principal real-world business event date for this transaction.',
    `payment_direction` STRING COMMENT 'Indicates whether the royalty payment is inbound (received by the company as licensor) or outbound (paid by the company as licensee). Critical for P&L classification and financial reporting.. Valid values are `inbound|outbound`',
    `payment_method` STRING COMMENT 'The financial instrument or mechanism used to execute the royalty payment (e.g., wire transfer, ACH, check, offset against receivables, or netting against other obligations).. Valid values are `wire_transfer|ach|check|offset|netting`',
    `payment_reference_number` STRING COMMENT 'Externally-known business identifier for this royalty payment transaction, typically matching the SAP FI document number or bank remittance reference used for reconciliation and audit trail.',
    `payment_status` STRING COMMENT 'Current lifecycle state of the royalty payment transaction. Tracks progression from draft calculation through approval, payment execution, and final settlement. [ENUM-REF-CANDIDATE: draft|pending|approved|paid|disputed|cancelled — promote to reference product if additional statuses are required]. Valid values are `draft|pending|approved|paid|disputed|cancelled`',
    `reconciliation_status` STRING COMMENT 'Current status of the royalty payment reconciliation process, indicating whether the payment has been matched against the licensees royalty report and confirmed as accurate. Supports royalty audit workflows.. Valid values are `unreconciled|in_review|reconciled|disputed`',
    `royalty_amount` DECIMAL(18,2) COMMENT 'Calculated royalty amount due for the calculation period, derived by applying the royalty rate to the applicable royalty basis (net sales, gross sales, or units sold). This is the principal monetary fact of the transaction.',
    `royalty_report_reference` STRING COMMENT 'Reference number or identifier of the royalty statement or sales report submitted by the licensee that forms the basis for this royalty payment calculation. Links the payment to the supporting documentation.',
    `royalty_tier_label` STRING COMMENT 'Label identifying the applicable royalty tier when the licensing agreement specifies tiered rates based on cumulative net sales thresholds (e.g., Tier 1: 0-$100M, Tier 2: $100M-$500M). Null if the agreement uses a flat rate.',
    `therapeutic_area` STRING COMMENT 'Therapeutic area classification of the licensed drug product (e.g., Oncology, Immunology, Rare Diseases). Supports portfolio-level royalty analytics and strategic lifecycle management decisions.',
    `total_payment_amount` DECIMAL(18,2) COMMENT 'Final net royalty payment amount after applying the royalty rate to the basis, enforcing any minimum royalty floor, and incorporating adjustments. This is the amount actually paid or received.',
    `units_sold` DECIMAL(18,2) COMMENT 'Number of units of the licensed product sold during the calculation period. Used as the royalty basis for unit-based royalty agreements. Expressed as DECIMAL to accommodate partial units or volume-based measures.',
    `updated_timestamp` TIMESTAMP COMMENT 'Timestamp when this royalty payment record was last modified. Supports change tracking, audit trail requirements, and data lineage in the Databricks Silver Layer.',
    `withholding_tax_amount` DECIMAL(18,2) COMMENT 'Amount of withholding tax deducted from the royalty payment at source, as required by applicable tax treaties between the licensor and licensee jurisdictions. Relevant for cross-border licensing arrangements.',
    `withholding_tax_rate` DECIMAL(18,2) COMMENT 'Applicable withholding tax rate (expressed as a decimal fraction) applied to the royalty payment based on the tax treaty between the relevant jurisdictions. Used to validate withholding tax amount calculations.',
    CONSTRAINT pk_royalty_payment PRIMARY KEY(`royalty_payment_id`)
) COMMENT 'Transactional record of royalty payments made or received under licensing agreements. Captures payment date, payment direction (inbound/outbound), royalty basis (net sales, units sold), royalty rate applied, calculation period, gross sales, net sales, deductions, royalty amount, currency, payment status, and reconciliation status. Supports financial reporting, royalty audits, and compliance with licensing agreement terms.';

CREATE OR REPLACE TABLE `pharmaceuticals_ecm`.`intellectual`.`fto_analysis` (
    `fto_analysis_id` BIGINT COMMENT 'Unique system-generated identifier for each Freedom-to-Operate (FTO) analysis or competitive IP watch record. Primary key for this entity.',
    `country_id` BIGINT COMMENT 'Foreign key linking to masterdata.country. Business justification: FTO analyses are jurisdiction-specific; critical for market entry risk assessment, product launch planning, and patent landscape analysis in target markets.',
    `drug_product_id` BIGINT COMMENT 'Foreign key linking to product.drug_product. Business justification: FTO opinions are product-specific for launch risk assessment, design-around strategy, and IP clearance. Essential for R&D and commercial decision-making. Removes denormalized product identifiers.',
    `drug_substance_id` BIGINT COMMENT 'Foreign key linking to product.drug_substance. Business justification: FTO analyses are conducted for drug substances (NCEs, biologics) before IND filing and manufacturing scale-up. IP teams need to link FTO analyses to specific drug substances to assess freedom-to-opera',
    `formulation_id` BIGINT COMMENT 'Foreign key linking to product.formulation. Business justification: FTO analyses are conducted for specific formulations before technology transfer and manufacturing scale-up. IP teams need to link FTO analyses to formulations to assess freedom-to-operate for formulat',
    `business_partner_id` BIGINT COMMENT 'Foreign key linking to masterdata.business_partner. Business justification: FTO analysis law firms are business partners in the vendor master. Linking enables legal spend tracking, AP payment processing, and outside counsel management. law_firm_name is a denormalized business',
    `cost_center_id` BIGINT COMMENT 'Foreign key linking to masterdata.cost_center. Business justification: FTO analyses are charged to requesting business units; required for cost allocation, chargeback processing, and legal spend tracking in pharmaceutical IP.',
    `inn_registry_id` BIGINT COMMENT 'Foreign key linking to masterdata.inn_registry. Business justification: FTO analyses are conducted for specific active ingredients (INNs) to assess freedom to operate before product launch. Substance-level FTO portfolio management and regulatory clearance tracking require',
    `patent_family_id` BIGINT COMMENT 'Foreign key linking to intellectual.patent_family. Business justification: FTO analyses in pharma are commonly scoped to entire patent families rather than individual patents, since a competitor product must clear all family members across jurisdictions. fto_analysis has no ',
    `patent_id` BIGINT COMMENT 'Foreign key linking to intellectual.patent. Business justification: Freedom-to-Operate analyses are conducted with respect to specific blocking patents. fto_analysis currently has no FK to patent despite being the core IP asset being analyzed. One patent can be the su',
    `affected_product_names` STRING COMMENT 'Comma-separated list of proprietary product names or INNs that are commercially affected by the FTO analysis findings or the competitor IP watch activity. Supports portfolio-level impact assessment and lifecycle management decisions.',
    `analysis_date` DATE COMMENT 'The date on which the FTO analysis was formally conducted or the opinion was rendered by the responsible attorney or firm. Represents the principal business event date for this record.',
    `analysis_number` STRING COMMENT 'Externally-known unique reference number assigned to the FTO analysis or IP watch record, used for tracking across legal, regulatory, and business functions. Format: FTO-YYYY-NNNNN.. Valid values are `^FTO-[0-9]{4}-[0-9]{5}$`',
    `analysis_status` STRING COMMENT 'Current lifecycle state of the FTO analysis record: draft (initiated, not yet reviewed), in_review (under attorney or committee review), completed (final opinion issued), superseded (replaced by a newer analysis), or cancelled.. Valid values are `draft|in_review|completed|superseded|cancelled`',
    `analysis_title` STRING COMMENT 'Descriptive title of the Freedom-to-Operate analysis or competitive IP watch record, summarizing the product, technology, or process under assessment.',
    `analysis_type` STRING COMMENT 'Classification of the analysis record: FTO assessment (go/no-go commercialization opinion), IP watch (ongoing competitor monitoring), patent landscape (broad mapping), clearance opinion (legal freedom-to-use), or freedom-to-use. Drives workflow and reporting.. Valid values are `fto_assessment|ip_watch|patent_landscape|clearance_opinion|freedom_to_use`',
    `competitor_filing_date` DATE COMMENT 'Date on which the competitor filed the patent application, ANDA, biosimilar application, or other regulatory/IP submission being monitored. Critical for calculating response timelines and exclusivity defense windows.',
    `competitor_name` STRING COMMENT 'Name of the competitor company whose IP activities are being monitored in this watch record (e.g., generic manufacturer filing an ANDA, biosimilar applicant, or third-party patent filer). Central to competitive intelligence.',
    `competitor_reference_number` STRING COMMENT 'Official reference number of the competitors filing being monitored, such as an ANDA application number, biosimilar BLA number, patent publication number, or IPR petition number. Enables direct lookup in regulatory and patent databases.',
    `conducting_attorney` STRING COMMENT 'Name of the internal patent attorney or external legal counsel responsible for conducting and signing off on the FTO analysis. Critical for attorney-client privilege tracking and legal accountability.',
    `confidentiality_level` STRING COMMENT 'Data classification level assigned to the FTO analysis record, governing access controls and information sharing: restricted (attorney-client privilege, highly sensitive), confidential (internal legal/IP team only), internal (general internal use), or public. Aligns with enterprise data governance policy.. Valid values are `restricted|confidential|internal|public`',
    `created_timestamp` TIMESTAMP COMMENT 'Timestamp when this FTO analysis record was first created in the system. Used for audit trail and data lineage tracking per 21 CFR Part 11 requirements.',
    `design_around_required` BOOLEAN COMMENT 'Indicates whether the FTO analysis concluded that a design-around strategy is required to avoid infringement of identified blocking patents before commercialization can proceed.',
    `dmf_reference_number` STRING COMMENT 'Reference number of the Drug Master File (DMF) associated with the drug substance or manufacturing process under FTO assessment, if applicable. Links the IP analysis to the CMC regulatory submission package.',
    `exclusivity_expiry_date` DATE COMMENT 'Date on which the relevant regulatory exclusivity period (orphan drug, data exclusivity, pediatric, NCE, etc.) expires for the assessed product. Determines the earliest date a competitor could receive approval for a generic or biosimilar.',
    `exclusivity_type` STRING COMMENT 'Type of regulatory exclusivity relevant to the FTO analysis or IP watch record: orphan_drug, data_exclusivity, pediatric, new_chemical_entity (NCE), biological, or market exclusivity. Informs the window of protection against generic or biosimilar entry. [ENUM-REF-CANDIDATE: orphan_drug|data_exclusivity|pediatric|new_chemical_entity|biological|market — promote to reference product]. Valid values are `orphan_drug|data_exclusivity|pediatric|new_chemical_entity|biological|market`',
    `final_opinion` STRING COMMENT 'The formal legal opinion rendered by the conducting attorney: clear (free to operate without infringement risk), conditional_clear (free to operate subject to design-arounds or licensing), blocked (cannot commercialize without infringing), inconclusive (insufficient information), or pending (opinion not yet issued).. Valid values are `clear|conditional_clear|blocked|inconclusive|pending`',
    `licensing_required` BOOLEAN COMMENT 'Indicates whether the FTO analysis concluded that a license must be obtained from a third-party patent holder before the assessed product or technology can be commercialized.',
    `litigation_flag` BOOLEAN COMMENT 'Indicates whether the FTO analysis or IP watch record is associated with active or anticipated patent litigation (e.g., Paragraph IV ANDA challenge, IPR petition, patent infringement suit). Triggers escalation to senior legal counsel.',
    `patent_expiry_relevance_date` DATE COMMENT 'The earliest expiry date among the blocking patents identified in the FTO analysis, representing the date after which the primary IP barrier may no longer apply. Critical for lifecycle management and generic/biosimilar entry defense planning.',
    `recommended_actions` STRING COMMENT 'Narrative description of recommended next steps arising from the FTO analysis, such as design-around strategies, licensing negotiations, patent challenge (IPR/PGR), freedom-to-use licensing, or further legal investigation. Drives IP strategy execution.',
    `requestor_department` STRING COMMENT 'Business department or function that initiated the FTO analysis request (e.g., R&D, Commercial, Regulatory Affairs, Legal). Used for workload tracking and cross-functional reporting.',
    `review_due_date` DATE COMMENT 'Scheduled date by which the FTO analysis or IP watch record must be reviewed and updated to reflect changes in the patent landscape, competitor activities, or product development status. Supports proactive IP portfolio management.',
    `risk_level` STRING COMMENT 'Overall IP infringement risk level assigned by the conducting attorney following the FTO analysis: high (significant blocking IP identified, commercialization at risk), medium (some risk, mitigation possible), low (minor risk, manageable), or negligible (no material blocking IP found).. Valid values are `high|medium|low|negligible`',
    `risk_rationale` STRING COMMENT 'Narrative explanation supporting the assigned risk level, summarizing the key blocking patents, claim analysis findings, and legal reasoning that led to the risk determination. Supports legal review and business decision-making.',
    `scope_description` STRING COMMENT 'Detailed narrative describing the scope of the FTO analysis, including the specific product features, process steps, formulation parameters, or technology elements assessed for potential third-party IP infringement.',
    `technology_area` STRING COMMENT 'Broad technology or therapeutic area classification of the subject matter under FTO assessment (e.g., oncology, immunology, rare diseases, formulation, manufacturing process, delivery device). Supports portfolio-level IP analytics.',
    `threat_assessment` STRING COMMENT 'Assessment of the competitive threat posed by the monitored competitor activity: critical (immediate commercial impact expected), high (significant risk to market exclusivity), medium (moderate risk requiring active response), low (limited near-term impact), or monitoring (no immediate action required).. Valid values are `critical|high|medium|low|monitoring`',
    `updated_timestamp` TIMESTAMP COMMENT 'Timestamp when this FTO analysis record was most recently modified. Supports audit trail, version control, and change management per 21 CFR Part 11.',
    `version_number` STRING COMMENT 'Version number of the FTO analysis document (e.g., 1.0, 2.1), tracking revisions and updates to the analysis over time. Supports document control and audit trail requirements under 21 CFR Part 11.. Valid values are `^[0-9]+.[0-9]+$`',
    `watch_type` STRING COMMENT 'For competitive IP watch records, classifies the type of competitor activity being monitored: patent_filing (new patent applications), anda_submission (Abbreviated New Drug Application), biosimilar_application (biosimilar filing), patent_challenge (IPR/PGR/opposition), regulatory_filing, or trademark. [ENUM-REF-CANDIDATE: patent_filing|anda_submission|biosimilar_application|patent_challenge|regulatory_filing|trademark — promote to reference product]. Valid values are `patent_filing|anda_submission|biosimilar_application|patent_challenge|regulatory_filing|trademark`',
    CONSTRAINT pk_fto_analysis PRIMARY KEY(`fto_analysis_id`)
) COMMENT 'Freedom-to-Operate (FTO) analysis and competitive IP watch records. Covers FTO assessments determining whether a product, process, or technology can be commercialized without infringing third-party IP rights, plus ongoing monitoring of competitor IP activities (patent filings, ANDA/505(b)(2) submissions, biosimilar applications, patent challenges). Captures analysis title, scope, requestor, conducting attorney or firm, analysis date, product or technology assessed, jurisdictions covered, identified blocking patents, risk level, recommended actions, final opinion, watch type, competitor identity, filing dates, reference numbers, technology area, affected products, and threat assessment. Supports go/no-go decisions for product development, commercial launch, and proactive IP defense strategy.';

CREATE OR REPLACE TABLE `pharmaceuticals_ecm`.`intellectual`.`patent_litigation` (
    `patent_litigation_id` BIGINT COMMENT 'Unique surrogate identifier for each patent litigation case record in the intellectual property portfolio management system.',
    `budget_id` BIGINT COMMENT 'Foreign key linking to finance.budget. Business justification: Patent litigation cases require dedicated legal budgets for outside counsel, expert witnesses, and settlement reserves. Finance links litigation cases to budget records to track actual vs. planned spe',
    `country_id` BIGINT COMMENT 'Foreign key linking to masterdata.country. Business justification: Litigation occurs in specific jurisdictions; required for legal strategy, financial reserves estimation, and paragraph IV defense planning in pharmaceutical patent disputes.',
    `legal_entity_id` BIGINT COMMENT 'Foreign key linking to masterdata.legal_entity. Business justification: Patent litigation is filed by or against specific internal legal entities. Legal entity-level litigation exposure reporting and financial provisioning (IAS 37) require knowing which legal entity is th',
    `drug_product_id` BIGINT COMMENT 'Foreign key linking to product.drug_product. Business justification: ANDA paragraph IV patent litigation is filed against specific drug products (NDA holders). Legal teams track litigation cases by drug product for revenue-at-risk analysis, 30-month stay management, an',
    `invoice_id` BIGINT COMMENT 'Foreign key linking to finance.invoice. Business justification: Patent litigation generates outside counsel invoices that must be linked to the specific litigation case for legal spend tracking, budget variance analysis, and SOX-compliant legal cost reporting. Pha',
    `cost_center_id` BIGINT COMMENT 'Foreign key linking to masterdata.cost_center. Business justification: Litigation costs are allocated to business units; essential for legal spend tracking, forecasting, and financial impact assessment of patent disputes.',
    `medicinal_product_id` BIGINT COMMENT 'Foreign key linking to product.medicinal_product. Business justification: Patent litigation targets specific products (Paragraph IV, biosimilar challenges). Essential for commercial risk assessment, legal spend tracking, revenue-at-risk forecasting. Removes denormalized pro',
    `orange_book_listing_id` BIGINT COMMENT 'Foreign key linking to intellectual.orange_book_listing. Business justification: Patent litigation in pharmaceuticals is often triggered by Paragraph IV certifications challenging Orange Book-listed patents. Linking patent_litigation to orange_book_listing tracks which Orange Book',
    `business_partner_id` BIGINT COMMENT 'Foreign key linking to masterdata.business_partner. Business justification: Outside counsel firms managing patent litigation are business partners in the vendor master. Linking enables legal spend management, matter management integration, and AP payment processing. outside_c',
    `patent_family_id` BIGINT COMMENT 'Foreign key linking to intellectual.patent_family. Business justification: Patent litigation in pharma frequently involves entire patent families — a Paragraph IV ANDA challenge or IPR petition may target all family members across jurisdictions simultaneously. patent_litigat',
    `patent_id` BIGINT COMMENT 'Foreign key linking to intellectual.patent. Business justification: A patent litigation case is fundamentally about asserting or defending a specific patent. patent_litigation currently has asserted_patent_numbers as a denormalized STRING, but a proper FK to the prima',
    `actual_legal_spend_usd` DECIMAL(18,2) COMMENT 'Cumulative actual legal fees and costs incurred to date for this litigation matter, expressed in US dollars. Sourced from SAP S/4HANA FI/CO module legal spend tracking. Used for legal budget management and P&L reporting.',
    `appeal_court` STRING COMMENT 'Name of the appellate court or tribunal hearing the appeal (e.g., U.S. Court of Appeals for the Federal Circuit, U.S. Supreme Court, EPO Board of Appeal). Null if no appeal has been filed.',
    `appeal_filed` BOOLEAN COMMENT 'Indicates whether an appeal has been filed following the trial court or PTAB judgment. True if an appeal is pending or has been decided; False if no appeal was filed.',
    `asserted_patent_numbers` STRING COMMENT 'Semicolon-delimited list of patent numbers (e.g., US9,123,456; US10,234,567) asserted or challenged in this litigation. These are the Orange Book-listed or Blue Book-listed patents at issue. Links to the patent portfolio for expiry and claim analysis.',
    `case_notes` STRING COMMENT 'Free-text field for internal legal team notes, strategic observations, and case-specific commentary. May include attorney work product summaries, risk assessments, and strategic recommendations. Classified as confidential due to potential attorney-client privilege content.',
    `case_number` STRING COMMENT 'Official court-assigned or tribunal-assigned docket number uniquely identifying the litigation case (e.g., civil action number, IPR petition number, PGR petition number). Serves as the primary external business identifier for cross-referencing with legal counsel and court records.',
    `case_priority` STRING COMMENT 'Internal priority classification assigned to the litigation case based on revenue at risk, strategic importance, and likelihood of adverse outcome. Critical cases receive executive-level oversight; high cases are monitored by senior IP counsel; medium and low cases follow standard legal management processes.. Valid values are `critical|high|medium|low`',
    `case_type` STRING COMMENT 'Classification of the litigation case by legal mechanism. Paragraph IV ANDA challenges arise under Hatch-Waxman; IPR and PGR are USPTO trial proceedings; patent infringement suits are district court actions; declaratory judgment actions are filed by generic/biosimilar challengers; biosimilar patent dance refers to BPCIA exchange proceedings. [ENUM-REF-CANDIDATE: paragraph_iv_anda|inter_partes_review|post_grant_review|patent_infringement|declaratory_judgment|biosimilar_patent_dance — promote to reference product]. Valid values are `paragraph_iv_anda|inter_partes_review|post_grant_review|patent_infringement|declaratory_judgment|biosimilar_patent_dance`',
    `court_or_tribunal` STRING COMMENT 'Name of the judicial or administrative body presiding over the case (e.g., U.S. District Court for the District of Delaware, USPTO Patent Trial and Appeal Board (PTAB), U.S. Court of Appeals for the Federal Circuit, European Patent Office Opposition Division).',
    `created_timestamp` TIMESTAMP COMMENT 'Timestamp when this patent litigation record was first created in the system, in ISO 8601 format (yyyy-MM-ddTHH:mm:ss.SSSXXX). Supports audit trail requirements and data lineage tracking.',
    `estimated_liability_usd` DECIMAL(18,2) COMMENT 'Managements best estimate of the potential financial exposure or liability associated with this litigation case, expressed in US dollars. Used for legal reserve provisioning, financial disclosure under ASC 450 (contingencies), and SOX compliance. Includes potential damages, lost profits, and legal costs.',
    `filing_date` DATE COMMENT 'Date on which the complaint, petition, or challenge was formally filed with the court or tribunal. For Paragraph IV ANDA challenges, this is the date the ANDA filer notified the NDA holder. Critical for calculating the 30-month stay period and litigation timelines.',
    `first_filer_status` BOOLEAN COMMENT 'Indicates whether the ANDA challenger is the first filer entitled to 180-day generic exclusivity under the Hatch-Waxman Act. True if the defendant holds first-filer status; False otherwise. Relevant for assessing the competitive landscape and timing of generic entry.',
    `institution_decision_date` DATE COMMENT 'Date on which the PTAB issued its decision on whether to institute the IPR or PGR trial. A decision to institute means the petition met the threshold for review. Null for non-PTAB proceedings.',
    `ipr_petition_number` STRING COMMENT 'USPTO-assigned petition number for Inter Partes Review proceedings before the Patent Trial and Appeal Board (PTAB). Format follows USPTO convention (e.g., IPR2023-01234). Null for non-IPR case types.',
    `judgment_date` DATE COMMENT 'Date on which the court or tribunal issued its final judgment, final written decision (for PTAB proceedings), or order. Null if the case has not yet reached judgment.',
    `lead_outside_counsel` STRING COMMENT 'Full name of the lead attorney at the outside counsel firm responsible for managing this litigation matter. Used for escalation, communication, and legal budget accountability.',
    `legal_budget_usd` DECIMAL(18,2) COMMENT 'Approved annual or total budget allocated for legal fees and costs associated with this litigation matter, expressed in US dollars. Used for variance analysis against actual legal spend and budget reforecasting.',
    `litigation_status` STRING COMMENT 'Current procedural status of the litigation case reflecting its lifecycle stage. Active cases are ongoing; settled cases have reached agreement; dismissed cases were terminated without judgment; judgment_entered reflects a court ruling; appealed cases are under appellate review; stayed cases are paused pending other proceedings; closed cases are fully resolved. [ENUM-REF-CANDIDATE: active|settled|dismissed|judgment_entered|appealed|stayed|closed — 7 candidates stripped; promote to reference product]',
    `next_key_milestone` STRING COMMENT 'Description of the next significant procedural or substantive milestone in the litigation (e.g., claim construction hearing, expert discovery deadline, summary judgment motion, PTAB oral argument, appellate briefing deadline). Used for litigation calendar management.',
    `next_milestone_date` DATE COMMENT 'Scheduled date for the next key procedural or substantive milestone in the litigation. Used for proactive legal calendar management and escalation triggers.',
    `outcome` STRING COMMENT 'Final outcome or resolution of the litigation case. Patent upheld means the challenged patent survived; patent invalidated means the patent was found invalid or unenforceable; infringement found or non-infringement found reflects district court rulings; settled indicates out-of-court resolution; dismissed indicates termination without merits ruling; consent judgment reflects agreed court order. Null for active cases. [ENUM-REF-CANDIDATE: patent_upheld|patent_invalidated|infringement_found|non_infringement_found|settled|dismissed|consent_judgment — promote to reference product]',
    `paragraph_iv_notice_date` DATE COMMENT 'Date on which the company received the formal Paragraph IV certification notice from the ANDA filer, as required under the Hatch-Waxman Act. Triggers the 45-day window to file suit and the 30-month stay. Null for non-Paragraph IV case types.',
    `plaintiff_name` STRING COMMENT 'Legal name of the party initiating the litigation (typically the innovator/NDA holder asserting patent rights, or the generic/biosimilar applicant filing a declaratory judgment action). May be the company itself or a subsidiary.',
    `revenue_at_risk_usd` DECIMAL(18,2) COMMENT 'Estimated annual revenue at risk if the litigation outcome is unfavorable and generic or biosimilar entry occurs earlier than the patent expiry date. Expressed in US dollars. Critical input for lifecycle management decisions and commercial strategy.',
    `settlement_date` DATE COMMENT 'Date on which a settlement agreement was executed between the parties, if the case was resolved through settlement rather than judgment. Null for cases resolved by judgment or still active.',
    `settlement_entry_date` DATE COMMENT 'Agreed date on which the generic or biosimilar entrant is permitted to launch its product under the terms of the settlement agreement. Critical for lifecycle management and revenue forecasting. Null for non-settlement outcomes.',
    `suit_filed_date` DATE COMMENT 'Date on which the NDA holder filed the patent infringement suit in response to the Paragraph IV notice, within the 45-day statutory window. Null for case types where the company is the defendant or for non-Hatch-Waxman proceedings.',
    `therapeutic_area` STRING COMMENT 'Therapeutic area or disease category associated with the drug product at the center of the litigation (e.g., Oncology, Immunology, Rare Diseases, Cardiovascular, Neuroscience). Enables portfolio-level analysis of litigation exposure by therapeutic area.',
    `thirty_month_stay_expiry_date` DATE COMMENT 'Date on which the automatic 30-month stay of FDA approval of the ANDA expires under the Hatch-Waxman Act. Calculated from the date the NDA holder received the Paragraph IV certification notice. Null for non-Hatch-Waxman case types. Critical for generic entry defense strategy.',
    `trial_date` DATE COMMENT 'Scheduled or actual date of the trial or oral hearing before the court or tribunal. For PTAB proceedings, this is the oral argument date. Null if trial has not been scheduled or the case settled prior to trial.',
    `updated_timestamp` TIMESTAMP COMMENT 'Timestamp when this patent litigation record was most recently modified, in ISO 8601 format (yyyy-MM-ddTHH:mm:ss.SSSXXX). Supports audit trail requirements and change tracking for compliance purposes.',
    CONSTRAINT pk_patent_litigation PRIMARY KEY(`patent_litigation_id`)
) COMMENT 'Tracks active and historical patent litigation cases including Paragraph IV ANDA challenges, inter partes review (IPR) petitions, post-grant review (PGR), patent infringement suits, and declaratory judgment actions. Captures case number, court or tribunal, case type, filing date, parties (plaintiff, defendant), asserted patents, accused products, litigation status, key milestones, outside counsel, estimated liability, and outcome. Critical for generic/biosimilar entry defense strategy and legal budget management.';

CREATE OR REPLACE TABLE `pharmaceuticals_ecm`.`intellectual`.`patent_prosecution` (
    `patent_prosecution_id` BIGINT COMMENT 'Unique surrogate identifier for each patent prosecution record in the portfolio management system. Primary key for the patent_prosecution data product.',
    `country_id` BIGINT COMMENT 'Foreign key linking to masterdata.country. Business justification: Patent prosecution is jurisdiction-specific; each prosecution record corresponds to a national/regional patent office. Prosecution cost tracking by jurisdiction and regulatory authority mapping requir',
    `internal_order_id` BIGINT COMMENT 'Foreign key linking to finance.internal_order. Business justification: Patent prosecution costs (annuity fees, filing fees, attorney costs) are tracked against SAP internal orders for IP cost controlling and capitalization decisions. Pharma IP finance teams require this ',
    `legal_entity_id` BIGINT COMMENT 'Foreign key linking to masterdata.legal_entity. Business justification: Patent prosecution is conducted on behalf of a specific legal entity (the patent applicant/owner). Legal entity-level IP asset reporting and transfer pricing of IP rights require this link. No existin',
    `cost_center_id` BIGINT COMMENT 'Foreign key linking to masterdata.cost_center. Business justification: Patent prosecution costs (annuity fees, attorney fees, filing fees) are tracked against cost centers for IP budget management and R&D cost capitalization under IAS 38. IP controllers require cost-cent',
    `patent_family_id` BIGINT COMMENT 'Foreign key linking to intellectual.patent_family. Business justification: Patent prosecution records track individual patent applications. Patent families group related applications filed across multiple jurisdictions that share a common priority. Each prosecution record sh',
    `patent_id` BIGINT COMMENT 'Foreign key linking to intellectual.patent. Business justification: Patent prosecution tracks the application process from filing through grant. When a patent is granted, the prosecution record should link to the resulting patent master record. The grant_number in pat',
    `business_partner_id` BIGINT COMMENT 'Foreign key linking to masterdata.business_partner. Business justification: Annuity paying agents are business partners in the vendor master; linking enables automated annuity payment processing and vendor spend analytics. paying_agent_name is a denormalized business_partner.',
    `abandonment_date` DATE COMMENT 'Date the application was formally abandoned, either expressly by the applicant or by operation of law (e.g., failure to respond to office action within statutory period or failure to pay issue fee). Null unless prosecution_stage = abandoned.',
    `annuity_due_date` DATE COMMENT 'Date by which the annuity or maintenance fee for the current fee year must be paid to maintain the patent in force. Failure to pay by this date (or within the grace period) results in patent lapse. Critical docketing field.',
    `annuity_fee_amount` DECIMAL(18,2) COMMENT 'Base annuity or maintenance fee amount due for the current fee year, in the currency specified by annuity_fee_currency. Used for IP budget forecasting and cost tracking across the patent portfolio.',
    `annuity_fee_currency` STRING COMMENT 'ISO 4217 three-letter currency code for the annuity fee amount (e.g., USD, EUR, JPY, GBP, CNY). Required for multi-currency portfolio cost consolidation and budget reporting.. Valid values are `^[A-Z]{3}$`',
    `annuity_fee_year` STRING COMMENT 'The renewal/annuity year number for which the most recent maintenance fee obligation applies (e.g., year 3, year 7, year 12). Annuity years are counted from the filing date in most jurisdictions. Used for fee schedule management and budget forecasting.',
    `annuity_grace_period_end_date` DATE COMMENT 'Last date on which the annuity fee can be paid with a surcharge before the patent lapses. Typically 6 months after annuity_due_date in most jurisdictions. After this date, the patent is irrevocably lapsed unless restoration procedures are available.',
    `annuity_payment_date` DATE COMMENT 'Actual date on which the annuity or maintenance fee was paid to the patent office or paying agent. Used to confirm timely payment and to calculate any applicable surcharges.',
    `annuity_payment_status` STRING COMMENT 'Current payment status of the annuity/maintenance fee obligation for the current fee year. Pending = not yet due or awaiting payment; Paid = confirmed payment received; Overdue = past due date, within grace period; Lapsed = grace period expired without payment; Waived = fee waived per applicable rules.. Valid values are `pending|paid|overdue|lapsed|waived`',
    `annuity_surcharge_amount` DECIMAL(18,2) COMMENT 'Late payment surcharge amount applied when the annuity fee is paid after the due date but within the grace period. Tracked separately from the base fee for cost analysis and to identify patterns of late payment.',
    `application_number` STRING COMMENT 'Official application number assigned by the patent office upon filing (e.g., US16/123456, EP21700001.2, PCT/US2023/012345). Serves as the primary external identifier for tracking prosecution status across jurisdictions.',
    `application_type` STRING COMMENT 'Classification of the patent application by filing type. Utility = standard non-provisional; Provisional = 12-month placeholder; PCT = Patent Cooperation Treaty international; Continuation/Divisional/CIP = derived from parent application. Determines prosecution rules and term calculations. CIP = Continuation-In-Part.. Valid values are `utility|provisional|PCT|continuation|divisional|CIP`',
    `claim_count` STRING COMMENT 'Total number of claims in the current version of the patent application or granted patent, including independent and dependent claims. Affects official filing fees in many jurisdictions and indicates the breadth of IP protection sought.',
    `cpc_classification` STRING COMMENT 'Cooperative Patent Classification (CPC) code assigned by USPTO or EPO (e.g., A61K 31/4745). More granular than IPC; used for patent analytics, freedom-to-operate (FTO) searches, and competitive landscape mapping.',
    `created_timestamp` TIMESTAMP COMMENT 'Timestamp when this patent prosecution record was first created in the IP docketing system. Supports audit trail requirements and data lineage tracking per 21 CFR Part 11 and SOX compliance.',
    `examiner_art_unit` STRING COMMENT 'Patent office art unit or examination division to which the application is assigned (e.g., USPTO Art Unit 1627 for pharmaceutical compositions). Informs prosecution strategy based on art unit allowance rates and examiner tendencies.',
    `examiner_name` STRING COMMENT 'Name of the patent examiner assigned to the application at the patent office. Used for prosecution strategy planning, examiner history analysis, and interview request management.',
    `expiry_date` DATE COMMENT 'Calculated date on which the patent expires, typically 20 years from the filing date subject to any patent term extensions (PTE), supplementary protection certificates (SPC), or pediatric exclusivity extensions. Critical for lifecycle management, generic entry forecasting, and LOE (loss of exclusivity) planning.',
    `filing_date` DATE COMMENT 'Date the patent application was officially filed with the patent office. Establishes the priority date for prior art purposes and is the anchor for calculating the 20-year patent term under most jurisdictions. Critical for patent term extension (PTE) and supplementary protection certificate (SPC) calculations.',
    `grant_date` DATE COMMENT 'Date the patent was officially granted by the patent office. Marks the start of enforceable patent rights and triggers the annuity/maintenance fee schedule in most jurisdictions. Null until prosecution_stage = granted.',
    `independent_claim_count` STRING COMMENT 'Number of independent claims in the application or granted patent. Independent claims define the broadest scope of protection and are the primary focus of validity and infringement analyses.',
    `invention_type` STRING COMMENT 'Pharmaceutical classification of the invention being patented. NCE (New Chemical Entity) = novel small molecule; NBE (New Biological Entity) = biologic/biosimilar; formulation = drug product composition; process = manufacturing/synthesis method; method_of_use = therapeutic indication; combination = multi-component therapy. Critical for lifecycle management and generic/biosimilar entry defense strategy.. Valid values are `NCE|NBE|formulation|process|method_of_use|combination`',
    `ipc_classification` STRING COMMENT 'International Patent Classification (IPC) code assigned to the application (e.g., A61K 31/00 for pharmaceutical preparations). Used for patent landscape analysis, prior art searches, and competitive intelligence. Multiple codes may be stored as a comma-separated string.',
    `last_office_action_date` DATE COMMENT 'Date of the most recent office action received from the patent office. Used to calculate the statutory response deadline and to trigger docketing alerts for prosecution attorneys.',
    `law_firm_name` STRING COMMENT 'Name of the external patent law firm engaged for prosecution of this application, if applicable. Used for vendor management, cost tracking, and conflict-of-interest monitoring across the IP portfolio.',
    `office_action_count` STRING COMMENT 'Total number of office actions (rejections, objections, or requirements) received from the patent office during prosecution of this application. Indicates prosecution complexity and is used for cost estimation and strategy assessment.',
    `office_action_type` STRING COMMENT 'Classification of the most recent office action received. Restriction = requirement to elect claims; Non-final = first substantive rejection; Final = final rejection after response; Advisory = after final response; Allowance/Notice of Allowance = claims approved for grant.. Valid values are `restriction|non-final|final|advisory|allowance|notice_of_allowance`',
    `parent_application_number` STRING COMMENT 'Application number of the parent patent application from which this application claims priority (applicable for continuation, divisional, or CIP applications). Used to reconstruct the patent family hierarchy and assess claim scope relative to the parent.',
    `patent_office_code` STRING COMMENT 'Two- or three-letter code identifying the national or regional patent office handling the application (e.g., US = USPTO, EP = EPO, JP = JPO/PMDA, CN = CNIPA, WO = WIPO PCT). Drives jurisdiction-specific deadline rules and annuity schedules. [ENUM-REF-CANDIDATE: US|EP|JP|CN|WO|GB|DE|FR|CA|AU|IN|KR|BR|MX|RU — promote to reference product]',
    `payment_confirmation_reference` STRING COMMENT 'Official confirmation or receipt reference number issued by the patent office or paying agent upon successful annuity fee payment. Serves as proof of payment for audit and compliance purposes.',
    `pct_application_number` STRING COMMENT 'PCT international application number (e.g., PCT/US2023/012345) if this national/regional application entered the national phase from a PCT filing. Links the national phase application to the international PCT prosecution record.',
    `priority_date` DATE COMMENT 'Earliest claimed priority date for the application, typically the filing date of the first-filed provisional or parent application in the priority chain. Governs prior art cutoff and is used in freedom-to-operate (FTO) analyses and patent validity assessments.',
    `prosecution_stage` STRING COMMENT 'Current stage of the patent application in the prosecution workflow lifecycle. Drives docketing actions, deadline calculations, and portfolio status reporting. Values: filed, examination, office_action_received, response_submitted, allowance, granted, abandoned. [ENUM-REF-CANDIDATE: filed|examination|office_action_received|response_submitted|allowance|granted|abandoned — 7 candidates stripped; promote to reference product]',
    `prosecution_strategy` STRING COMMENT 'Free-text description of the prosecution strategy adopted for this application, including claim amendment approach, interview strategy, appeal considerations, and alignment with the broader IP lifecycle management plan. Attorney-client privileged content.',
    `publication_date` DATE COMMENT 'Date the patent application was published by the patent office, typically 18 months after the earliest priority date. Marks the point at which the application enters the public domain and becomes citable prior art.',
    `publication_number` STRING COMMENT 'Official publication number assigned by the patent office upon publication of the application (e.g., US20230123456A1, WO2023/012345A1). Distinct from the application number; used for public citation and prior art searches.',
    `response_deadline` DATE COMMENT 'Statutory or extended deadline by which a response to the most recent office action must be filed to avoid abandonment. Calculated from last_office_action_date per jurisdiction-specific rules. Critical docketing field — failure to meet this deadline results in application abandonment.',
    `updated_timestamp` TIMESTAMP COMMENT 'Timestamp of the most recent update to this patent prosecution record. Used for change tracking, data synchronization with source docketing systems (e.g., Veeva Vault RIM, Anaqua), and audit compliance.',
    CONSTRAINT pk_patent_prosecution PRIMARY KEY(`patent_prosecution_id`)
) COMMENT 'Tracks patent application prosecution workflow from filing through grant or abandonment, including all annuity and maintenance fee payment obligations across all jurisdictions. Captures application number, prosecution stage, patent office, examiner, office actions received, response deadlines, prosecution attorney, prosecution strategy, and complete annuity/maintenance fee history (fee year, due dates, amounts, currencies, payment status, paying agents, confirmation receipts, grace periods, surcharge amounts). Failure to pay annuities results in patent lapse. Supports docketing, deadline management, fee compliance, cost tracking, portfolio maintenance operations, and annuity budget forecasting.';

CREATE OR REPLACE TABLE `pharmaceuticals_ecm`.`intellectual`.`patent_term_extension` (
    `patent_term_extension_id` BIGINT COMMENT 'Unique surrogate identifier for each patent term extension or supplementary protection certificate record in the intellectual property portfolio. Primary key for this entity.',
    `country_id` BIGINT COMMENT 'Foreign key linking to masterdata.country. Business justification: PTEs are jurisdiction-specific; critical for patent expiry forecasting, lifecycle management, and market-specific exclusivity planning in pharmaceutical commercialization.',
    `drug_product_id` BIGINT COMMENT 'Foreign key linking to product.drug_product. Business justification: PTEs granted for specific approved drug products (formulation-level precision beyond existing medicinal_product_id). Essential for LOE forecasting and regulatory strategy. Removes denormalized inn.',
    `drug_substance_id` BIGINT COMMENT 'Foreign key linking to product.drug_substance. Business justification: Patent term extensions are granted for the active ingredient (drug substance) that was subject to regulatory review. FDA PTE and EU SPC applications reference the specific drug substance. Regulatory a',
    `legal_entity_id` BIGINT COMMENT 'Foreign key linking to masterdata.legal_entity. Business justification: PTE/SPC applications are filed by the Marketing Authorization Holder (a specific legal entity). Legal entity-level IP asset reporting and regulatory submission tracking require this link. No existing ',
    `cost_center_id` BIGINT COMMENT 'Foreign key linking to masterdata.cost_center. Business justification: PTE/SPC application costs and associated legal fees are tracked against cost centers for IP budget management and R&D capitalization. IP finance teams require cost-center-level PTE spend reporting. No',
    `inn_registry_id` BIGINT COMMENT 'Foreign key linking to masterdata.inn_registry. Business justification: PTEs and SPCs are granted for specific active substances (INNs). Substance-level exclusivity management and LOE planning require INN linkage. atc_code on patent_term_extension is a classification, not',
    `medicinal_product_id` BIGINT COMMENT 'Reference to the drug product (Drug Product / Finished Dosage Form) for which the marketing authorization was obtained and which forms the basis of the extension application. Links the extension to the commercial product in the master data.',
    `patent_id` BIGINT COMMENT 'Reference to the underlying base patent record in the IP portfolio for which this term extension or SPC is being sought. Links the extension to the specific patent being extended.',
    `adjusted_expiry_date` DATE COMMENT 'The new patent expiry date after application of the granted term extension or SPC. Calculated as base_patent_expiry_date plus granted_extension_days. This is the Loss of Exclusivity (LOE) date for the product in this jurisdiction and is the primary output used in lifecycle management and generic/biosimilar entry defense strategies.',
    `applicant_delay_days` STRING COMMENT 'Number of days deducted from the regulatory review period due to delays attributable to the applicant (e.g., failure to respond to FDA requests within the prescribed period). Reduces the calculated extension duration under 35 U.S.C. § 156(c)(1). Tracked for audit and dispute resolution purposes.',
    `application_number` STRING COMMENT 'The official application number assigned by the granting authority (e.g., USPTO, EPO, UKIPO, JPO) when the patent term extension or SPC application was filed. Serves as the primary external business identifier for tracking the application through the regulatory process.',
    `approval_phase_start_date` DATE COMMENT 'For US PTE calculations: the date on which the regulatory approval phase began, typically the date of NDA/BLA submission to the FDA. Used to calculate the approval phase component of the regulatory review period under 35 U.S.C. § 156(g)(1)(B).',
    `atc_code` STRING COMMENT 'The WHO Anatomical Therapeutic Chemical (ATC) classification code assigned to the active substance covered by the extension. Provides standardized classification for cross-portfolio analytics, competitive intelligence, and regulatory reporting.. Valid values are `^[A-Z][0-9]{2}[A-Z]{2}[0-9]{2}$`',
    `base_patent_expiry_date` DATE COMMENT 'The original expiry date of the underlying base patent before any term extension or adjustment is applied. Used as the baseline for calculating the adjusted expiry date and the duration of the extension period.',
    `base_patent_number` STRING COMMENT 'The official patent number of the underlying patent for which the term extension or SPC is sought (e.g., US10,123,456 or EP1234567). For SPC purposes, this is the basic patent as defined under Article 1(c) of EU Regulation 469/2009. Retained as a denormalized field for direct reference without joining to the patent table.',
    `calculated_extension_days` STRING COMMENT 'The number of days of patent term extension calculated based on the regulatory review period formula. For US PTE: one-half of the testing phase plus the approval phase, capped at 5 years with remaining patent life not exceeding 14 years post-approval. For EU SPC: period between IND filing and MA grant minus 5 years, capped at 5 years.',
    `created_timestamp` TIMESTAMP COMMENT 'Timestamp when this patent term extension record was first created in the system. Used for audit trail and data lineage tracking in compliance with 21 CFR Part 11 electronic records requirements.',
    `data_exclusivity_expiry_date` DATE COMMENT 'The date on which regulatory data exclusivity (also known as data protection) expires for the product in this jurisdiction. In the EU, this is 8+2+1 years from first authorization; in the US, 5 years for NCEs or 12 years for biologics. Tracked alongside PTE/SPC to determine the complete exclusivity landscape.',
    `decision_status` STRING COMMENT 'Current lifecycle status of the patent term extension or SPC application. Tracks the application from initial drafting through filing, examination, and final decision by the granting authority. Critical for LOE (Loss of Exclusivity) date calculation and portfolio management. [ENUM-REF-CANDIDATE: draft|filed|under_review|granted|refused|withdrawn|appealed|lapsed|invalidated — promote to reference product]',
    `external_counsel_reference` STRING COMMENT 'Reference identifier or name of the external patent law firm or legal counsel managing this patent term extension or SPC application. Used for coordination of legal strategy, correspondence tracking, and matter management. Marked confidential as it reflects privileged legal relationships.',
    `filing_date` DATE COMMENT 'The date on which the patent term extension or SPC application was formally filed with the granting authority. For US PTE, must be filed within 60 days of first marketing approval. For EU SPC, must be filed within 6 months of marketing authorization grant. Critical for determining application validity.',
    `grant_date` DATE COMMENT 'The date on which the granting authority officially granted the patent term extension or SPC. Null if the application has not yet been decided or was refused/withdrawn. Used to confirm the effective start of the extended protection period.',
    `granted_extension_days` STRING COMMENT 'The actual number of days of patent term extension officially granted by the granting authority. May differ from the calculated extension if the authority applies different determinations of the regulatory review period or applicant delay deductions. Null until the extension is formally granted.',
    `granting_authority` STRING COMMENT 'Name of the national or regional intellectual property office responsible for examining and granting the patent term extension or SPC (e.g., USPTO, EPO, UKIPO, JPO, CIPO, IP Australia). Determines procedural rules and timelines.',
    `loe_date` DATE COMMENT 'The effective Loss of Exclusivity (LOE) date for the product in this jurisdiction, accounting for all applicable exclusivity mechanisms (PTE/SPC, pediatric extension, orphan drug exclusivity, data exclusivity). This is the single most critical date for commercial planning, generic/biosimilar entry defense, and lifecycle management strategy. Represents the date after which generic or biosimilar competition may legally enter the market.',
    `marketing_authorization_date` DATE COMMENT 'The date on which the first marketing authorization for the product was granted in the relevant jurisdiction. This date is critical for calculating the regulatory review period and the permissible extension duration under Hatch-Waxman PTE and EU SPC frameworks.',
    `marketing_authorization_number` STRING COMMENT 'The official marketing authorization number (NDA number, BLA number, EU MA number, or national equivalent) that forms the regulatory basis for the extension application. For EU SPC, this is the first authorization to place the product on the market in the Community per Article 3(b) of Regulation 469/2009.',
    `mechanism_type` STRING COMMENT 'Classification of the patent term extension mechanism. PTE = US Hatch-Waxman Patent Term Extension under 35 U.S.C. § 156; SPC = EU/UK Supplementary Protection Certificate under EC Regulation 469/2009; national_equivalent = country-specific analogous mechanisms (e.g., Japan, Canada, Australia); pediatric_extension = additional 6-month pediatric exclusivity; data_exclusivity = regulatory data protection period. [ENUM-REF-CANDIDATE: PTE|SPC|national_equivalent|pediatric_extension|data_exclusivity|regulatory_data_protection — promote to reference product]. Valid values are `PTE|SPC|national_equivalent|pediatric_extension|data_exclusivity`',
    `notes` STRING COMMENT 'Free-text field for capturing additional context, legal strategy notes, authority correspondence summaries, or other relevant information pertaining to this patent term extension or SPC record that is not captured in structured fields. Used by IP counsel and regulatory affairs teams.',
    `opposition_date` DATE COMMENT 'The date on which a third-party opposition, invalidity action, or equivalent challenge was filed against this patent term extension or SPC. Null if no opposition has been filed. Used to track litigation timelines and coordinate with legal counsel.',
    `opposition_filed` BOOLEAN COMMENT 'Indicates whether a third party (e.g., generic manufacturer, biosimilar applicant) has filed an opposition, invalidity action, or equivalent challenge against this patent term extension or SPC. True triggers escalation to the legal team for litigation management and LOE date reassessment.',
    `orphan_drug_exclusivity` BOOLEAN COMMENT 'Indicates whether the product covered by this extension also benefits from orphan drug exclusivity (7 years in the US under the Orphan Drug Act, 10 years in the EU under Regulation (EC) No 141/2000). Used in conjunction with PTE/SPC to determine the effective exclusivity cliff date.',
    `pediatric_extension_eligible` BOOLEAN COMMENT 'Indicates whether this patent term extension or SPC is eligible for an additional 6-month pediatric extension under the US Best Pharmaceuticals for Children Act (BPCA) or EU Paediatric Regulation (EC) No 1901/2006. True if a Written Request (US) or Paediatric Investigation Plan (EU) has been completed and accepted.',
    `pediatric_extension_granted` BOOLEAN COMMENT 'Indicates whether the additional 6-month pediatric extension has been formally granted on top of the base PTE or SPC. Distinct from eligibility — this flag confirms the authority has approved the pediatric supplement. When True, the adjusted_expiry_date should reflect the additional 6 months.',
    `regulatory_review_period_days` STRING COMMENT 'The total number of days of the regulatory review period as determined by the granting authority. For US PTE, this is the period from IND filing to NDA/BLA approval, reduced by any applicant-caused delays. Directly determines the maximum permissible extension duration under 35 U.S.C. § 156.',
    `spc_product_definition` STRING COMMENT 'For EU/UK SPC applications only: the definition of the product as per Article 1(b) of EU Regulation 469/2009, specifying the active ingredient or combination of active ingredients of a medicinal product. This definition determines the scope of SPC protection and is critical for freedom-to-operate analyses and generic entry defense.',
    `testing_phase_start_date` DATE COMMENT 'For US PTE calculations: the date on which the regulatory review testing phase began, typically the date of IND (Investigational New Drug) application submission. Used to calculate the testing phase component of the regulatory review period under 35 U.S.C. § 156(g)(1).',
    `therapeutic_area` STRING COMMENT 'The therapeutic area or disease indication for which the drug product covered by the extension is approved (e.g., Oncology, Immunology, Rare Diseases, Cardiovascular, Neurology). Used for portfolio analytics, lifecycle management planning, and commercial strategy alignment.',
    `updated_timestamp` TIMESTAMP COMMENT 'Timestamp when this patent term extension record was most recently modified. Supports audit trail requirements and change tracking for IP portfolio management and regulatory compliance.',
    `veeva_vault_document_reference` STRING COMMENT 'The document identifier in Veeva Vault RIM (Regulatory Information Management) where the official extension application documents, correspondence with the granting authority, and supporting regulatory dossier are stored. Enables direct navigation from this record to the source regulatory documents.',
    CONSTRAINT pk_patent_term_extension PRIMARY KEY(`patent_term_extension_id`)
) COMMENT 'Records all patent term extension and supplementary protection mechanisms across global jurisdictions that compensate for regulatory review time lost during drug approval. Covers US Hatch-Waxman Patent Term Extension (PTE), EU/UK Supplementary Protection Certificates (SPC), Japanese patent term extension, and equivalent national mechanisms. Captures application number, mechanism type (PTE, SPC, national equivalent), filing date, patent reference, product reference, marketing authorization reference, regulatory review period, calculated/granted extension duration, adjusted expiry date, granting authority, decision status, SPC-specific fields (basic patent, product definition per Article 1(b)), and pediatric extension eligibility. Single source of truth for all patent term adjustments — critical for accurate LOE date calculation across all markets.';

CREATE OR REPLACE TABLE `pharmaceuticals_ecm`.`intellectual`.`orange_book_listing` (
    `orange_book_listing_id` BIGINT COMMENT 'Unique surrogate identifier for each Orange Book listing record in the intellectual property portfolio system. Primary key for this data product.',
    `drug_product_id` BIGINT COMMENT 'Foreign key linking to product.drug_product. Business justification: Orange Book listings reference specific drug products (NDC-level). Essential for generic competition monitoring, Paragraph IV strategy, and patent-product linkage accuracy. Removes denormalized identi',
    `exclusivity_period_id` BIGINT COMMENT 'Foreign key linking to intellectual.exclusivity_period. Business justification: FDA Orange Book listings include both patent and exclusivity information. The exclusivity_code and exclusivity_expiry_date (STRING, DATE) should be replaced with a FK to exclusivity_period.exclusivity',
    `legal_entity_id` BIGINT COMMENT 'Foreign key linking to masterdata.legal_entity. Business justification: Orange Book listings are held by specific legal entities (NDA holders). Legal entity-level IP portfolio reporting and paragraph IV litigation tracking require this link. applicant_name is a denormaliz',
    `atc_classification_id` BIGINT COMMENT 'Foreign key linking to masterdata.atc_classification. Business justification: Orange Book listings are classified by ATC for therapeutic area portfolio management and competitive intelligence. atc_code on orange_book_listing is a denormalized representation of atc_classificatio',
    `inn_registry_id` BIGINT COMMENT 'Foreign key linking to masterdata.inn_registry. Business justification: Orange Book listings are for specific drug substances (INNs). Substance-level patent linkage analysis and generic entry monitoring (paragraph IV challenges) require INN linkage. A pharma IP expert exp',
    `masterdata_ndc_code_id` BIGINT COMMENT 'Foreign key linking to masterdata.ndc_code. Business justification: Orange Book listings reference specific NDC codes; required for regulatory compliance, paragraph IV defense, and product-patent linkage tracking.',
    `patent_id` BIGINT COMMENT 'Foreign key linking to intellectual.patent. Business justification: FDA Orange Book listings reference specific patents that protect approved drug products. The patent_number (STRING) should be replaced with a FK to patent.patent_id to link the regulatory listing to t',
    `anda_first_filer_flag` BOOLEAN COMMENT 'Indicates whether a first-filer ANDA applicant has been identified for this patent listing, triggering the 180-day generic exclusivity period under Hatch-Waxman. True if a first filer has been designated; False otherwise. Affects the timing of subsequent generic approvals.',
    `created_timestamp` TIMESTAMP COMMENT 'Timestamp when this Orange Book listing record was first created in the data product. Supports audit trail requirements under 21 CFR Part 11 and data lineage tracking in the Silver Layer lakehouse.',
    `delisting_date` DATE COMMENT 'Date on which the patent or exclusivity was removed from the FDA Orange Book, either voluntarily by the NDA holder or by FDA order. Null if the listing remains active. Relevant for tracking generic entry eligibility changes.',
    `dosage_form` STRING COMMENT 'Physical form of the finished dosage form (FDF) as listed in the Orange Book (e.g., tablet, capsule, injection, solution, patch). Determines therapeutic equivalence evaluation and generic substitutability. [ENUM-REF-CANDIDATE: tablet|capsule|injection|solution|patch|cream|suspension|powder|gel|suppository — promote to reference product]',
    `first_generic_eligibility_date` DATE COMMENT 'Earliest date on which a generic drug product may receive final FDA approval, accounting for both patent expiry and exclusivity expiry dates. Derived from the later of patent expiry, exclusivity expiry, and 30-month stay expiry. Critical for lifecycle management and loss-of-exclusivity (LOE) planning.',
    `listing_date` DATE COMMENT 'Date on which the patent or exclusivity was first listed in the FDA Orange Book by the NDA holder. Establishes the effective date of the listing for Paragraph IV certification and 30-month stay calculations.',
    `listing_status` STRING COMMENT 'Current status of the Orange Book listing record. Active indicates the patent or exclusivity is currently listed and enforceable. Delisted indicates the NDA holder has removed the listing. Withdrawn indicates FDA-initiated removal. Pending indicates submission under review. Corrected indicates an amendment was filed.. Valid values are `active|delisted|withdrawn|pending|corrected`',
    `litigation_status` STRING COMMENT 'Current status of patent infringement litigation associated with this Orange Book listing, typically arising from a Paragraph IV certification. Tracks whether litigation is active, settled, or resolved by court judgment. Informs LOE risk assessment and legal strategy. [ENUM-REF-CANDIDATE: none|active|settled|judgment_for_patentee|judgment_for_challenger|appeal_pending|dismissed — promote to reference product]. Valid values are `none|active|settled|judgment_for_patentee|judgment_for_challenger|appeal_pending`',
    `market` STRING COMMENT 'Regulatory market or jurisdiction for which this listing record applies. US for FDA Orange Book; EU for EMA Article 10 reference product listing; UK for MHRA; JP for PMDA; CN for NMPA. Enables multi-market IP portfolio management. [ENUM-REF-CANDIDATE: US|EU|UK|JP|CN|CA|AU|BR|IN|KR — 10 candidates stripped; promote to reference product]',
    `nda_number` STRING COMMENT 'FDA-assigned application number (NDA, ANDA, or BLA) under which the drug product is approved and listed in the Orange Book. Governs which patents and exclusivities are associated with the approved product.. Valid values are `^(NDA|ANDA|BLA)[0-9]{6}$`',
    `orphan_drug_designation_flag` BOOLEAN COMMENT 'Indicates whether the listed drug product holds an FDA Orphan Drug Designation (ODD), conferring 7-year market exclusivity upon approval. True if ODD is active; False otherwise. Relevant for rare disease portfolio strategy and generic entry defense.',
    `paragraph_iv_date` DATE COMMENT 'Date on which the first Paragraph IV certification was received by the NDA holder for this listed patent. Initiates the 45-day window to file patent infringement suit and triggers the 30-month stay clock if suit is filed.',
    `paragraph_iv_flag` BOOLEAN COMMENT 'Indicates whether a Paragraph IV certification has been filed by an ANDA applicant challenging this listed patent as invalid, unenforceable, or not infringed. True triggers the 45-day notice period and potential 30-month stay of ANDA approval.',
    `patent_expiry_date` DATE COMMENT 'Date on which the listed patent expires as published in the FDA Orange Book. This date directly governs the earliest date a generic applicant may receive final approval absent a Paragraph IV challenge or court ruling.',
    `patent_type` STRING COMMENT 'Classification of the listed patent as covering the drug substance (active ingredient), drug product (formulation/composition), or method of use. Determines the nature of Paragraph IV challenges and carve-out labeling strategies.. Valid values are `drug_substance|drug_product|method_of_use`',
    `patent_use_code` STRING COMMENT 'FDA-assigned use code (e.g., U-001) that identifies the specific approved method of use covered by the listed patent. Required for method-of-use patents; determines the scope of Paragraph IV certifications and carve-out labeling eligibility.. Valid values are `^U-[0-9]{3,4}$`',
    `pediatric_exclusivity_flag` BOOLEAN COMMENT 'Indicates whether a 6-month pediatric exclusivity extension has been granted under the Best Pharmaceuticals for Children Act (BPCA), attaching to all existing patents and exclusivities for the listed product. True if pediatric exclusivity is in effect.',
    `reference_listed_drug_flag` BOOLEAN COMMENT 'Indicates whether this NDA product is designated as the Reference Listed Drug (RLD) against which ANDA applicants must demonstrate bioequivalence. True if the product is the RLD; False if it is a non-RLD listed product.',
    `rems_flag` BOOLEAN COMMENT 'Indicates whether the listed drug product is subject to an FDA-approved Risk Evaluation and Mitigation Strategy (REMS). REMS requirements may affect generic applicant ability to demonstrate shared REMS compliance, impacting generic entry timelines.',
    `route_of_administration` STRING COMMENT 'Route by which the drug product is administered (e.g., oral, intravenous, topical, subcutaneous). Used in therapeutic equivalence evaluations and generic entry assessments. [ENUM-REF-CANDIDATE: oral|intravenous|subcutaneous|intramuscular|topical|inhalation|transdermal|ophthalmic — promote to reference product]',
    `spc_expiry_date` DATE COMMENT 'Date on which the Supplementary Protection Certificate (SPC) expires in the relevant EU/UK jurisdiction. Represents the effective end of patent-based market protection for the listed product in that market.',
    `spc_number` STRING COMMENT 'Reference number of the Supplementary Protection Certificate (SPC) granted in EU/UK jurisdictions to extend patent protection beyond the standard 20-year term for medicinal products. Applicable for EU and UK market listings; null for US Orange Book entries.',
    `strength` STRING COMMENT 'Labeled strength of the drug product as listed in the Orange Book (e.g., 10 mg, 500 mg/5 mL). Strength is a key differentiator for therapeutic equivalence and generic substitution eligibility.',
    `submission_date` DATE COMMENT 'Date on which the NDA holder submitted the patent or exclusivity information to the FDA for Orange Book listing. Must occur within 30 days of NDA approval or patent grant per 21 CFR Part 314.53(d).',
    `therapeutic_equivalence_code` STRING COMMENT 'FDA therapeutic equivalence evaluation code assigned to the drug product in the Orange Book (e.g., AB, AA, BC, BX). A codes indicate therapeutically equivalent to the RLD; B codes indicate not therapeutically equivalent. Drives pharmacy substitution decisions and formulary management.. Valid values are `^(A[A-Z]|B[A-Z]?)$`',
    `thirty_month_stay_expiry_date` DATE COMMENT 'Date on which the 30-month stay of ANDA approval expires following a timely-filed patent infringement suit in response to a Paragraph IV certification. After this date, FDA may grant final ANDA approval regardless of ongoing litigation outcome.',
    `updated_timestamp` TIMESTAMP COMMENT 'Timestamp when this Orange Book listing record was last modified in the data product. Supports change tracking, audit compliance under 21 CFR Part 11, and Silver Layer data freshness monitoring.',
    `veeva_vault_doc_reference` STRING COMMENT 'Reference identifier for the corresponding Orange Book listing submission document stored in Veeva Vault RIM (Regulatory Information Management). Enables traceability between the data record and the source regulatory document.',
    CONSTRAINT pk_orange_book_listing PRIMARY KEY(`orange_book_listing_id`)
) COMMENT 'Records of patents and exclusivities listed in the FDA Orange Book (Approved Drug Products with Therapeutic Equivalence Evaluations) for each NDA/ANDA product. Captures NDA number, product name, active ingredient, dosage form, strength, listed patent number, patent expiry date, exclusivity code, exclusivity expiry date, and listing status. Directly governs generic entry timelines and Paragraph IV challenge eligibility. Analogous listings for EU (Article 10 reference) and other markets are also captured.';

CREATE OR REPLACE TABLE `pharmaceuticals_ecm`.`intellectual`.`licensed_patent_schedule` (
    `licensed_patent_schedule_id` BIGINT COMMENT 'Primary key for the licensed_patent_schedule association',
    `licensing_agreement_id` BIGINT COMMENT 'Foreign key linking to the licensing agreement under which this patent is licensed. Identifies the deal, parties, territory, and financial terms governing this patents inclusion.',
    `patent_id` BIGINT COMMENT 'Foreign key linking to the specific patent covered under this licensing agreement. Identifies the IP asset whose rights are being granted.',
    `effective_date` DATE COMMENT 'Date on which this specific patents coverage under the licensing agreement becomes operative. May differ from the agreements overall effective_date when patents are added to an existing agreement via amendment (e.g., a continuation patent granted after deal signing is added to the schedule mid-term).',
    `exclusivity_type` STRING COMMENT 'Scope of exclusivity granted for this specific patent under this agreement. A single licensing agreement may grant exclusive rights to one patent and non-exclusive rights to another in the same schedule. Cannot reside on licensing_agreement (which captures overall deal exclusivity) or on patent (which may be licensed exclusively to one partner and non-exclusively to another).',
    `expiry_date` DATE COMMENT 'Date on which this patents coverage under the agreement terminates. May be driven by the patents own expiry, the agreements expiry, or a negotiated earlier termination for this specific patent. Enables LOE planning at the patent-agreement intersection level.',
    `licensed_scope` STRING COMMENT 'Narrative or structured description of which patent claims, fields of use, or indications are licensed under this agreement for this specific patent. A patent may be partially licensed (e.g., only method-of-use claims, not composition claims). Cannot reside on the agreement (varies per patent) or on the patent (varies per agreement).',
    `royalty_rate_per_patent` DECIMAL(18,2) COMMENT 'The royalty rate (expressed as a percentage of net sales or a fixed per-unit amount) applicable specifically to this patent under this agreement. In multi-patent deals, individual patents may carry different royalty rates reflecting their relative commercial importance. Cannot reside on licensing_agreement (which may aggregate rates) or on patent (which may be licensed at different rates to different partners).',
    `schedule_status` STRING COMMENT 'Current lifecycle status of this patents inclusion in the licensed patent schedule. Supports tracking of patents added, removed, or suspended from coverage during the agreement term without requiring deletion of the historical record.',
    `sublicensing_permitted` BOOLEAN COMMENT 'Indicates whether the licensee is contractually permitted to sublicense this specific patent to third parties under this agreement. Sublicensing rights may be granted for some patents in a schedule but not others, particularly where the licensor retains tighter control over foundational composition-of-matter patents.',
    CONSTRAINT pk_licensed_patent_schedule PRIMARY KEY(`licensed_patent_schedule_id`)
) COMMENT 'This association product represents the Contract between licensing_agreement and patent. It captures the formal schedule of intellectual property assets covered under each licensing agreement, recording the specific patents licensed, the per-patent royalty rate, the scope of licensed claims, exclusivity type, and sublicensing rights for each patent-agreement combination. Each record links one licensing_agreement to one patent with attributes that exist only in the context of this contractual relationship — they cannot reside on the agreement (which spans multiple patents) nor on the patent (which may be licensed under multiple agreements with different terms).. Existence Justification: In pharmaceutical IP management, a single licensing agreement routinely covers a portfolio of multiple patents (e.g., a composition-of-matter patent plus a method-of-use patent plus a formulation patent), and a single patent can be licensed under multiple separate agreements to different licensees in different territories or fields of use. The business actively manages this relationship as a Licensed Patent Schedule — a formal exhibit attached to every licensing agreement that lists each covered patent with its own royalty rate, effective dates, and exclusivity scope. This is not an analytical correlation; it is an operationally managed, legally binding schedule that deal managers create, amend, and terminate throughout the agreement lifecycle.';

